import Dashboard from "./pages/Dashboard";

function App() {
  return <Dashboard />;
}

export default App;

import { useState, useEffect, useRef } from "react";
import Sidebar from "../components/Sidebar";
import DigitsDistribution from "../components/DigitsDistribution";
import EvenOddAnalysis from "../components/EvenOddAnalysis";
import OverUnderAnalysis from "../components/OverUnderAnalysis";
import FooterPanels from "../components/FooterPanels";

export type Market =
  | "Volatility 10"
  | "Volatility 25"
  | "Volatility 50"
  | "Volatility 75"
  | "Volatility 100"
  | "Boom 1000"
  | "Crash 1000"
  | "Jump 25"
  | "Jump 50"
  | "Jump 75"
  | "Jump 100"
  | "Step Index";

export type ActiveView =
  | "Digits Analysis"
  | "Even / Odd"
  | "Over / Under"
  | "Matches / Differs"
  | "AI Prediction"
  | "Volatility Indexes"
  | "Smart Signals";

export type DigitStats = {
  counts: number[];
  total: number;
  lastDigit: number;
  percentages: string[];
  topDigits: number[];
  bottomDigits: number[];
  evenPercent: number;
  oddPercent: number;
  overPercent: number;
  underPercent: number;
  signal: string;
  matchesProbability: number;
  differsProbability: number;
  aiConfidence: number;
};

function computeStats(counts: number[], lastDigit: number): DigitStats {
  const total = counts.reduce((a, b) => a + b, 0);
  if (total === 0) {
    return {
      counts,
      total,
      lastDigit,
      percentages: Array(10).fill("0.0"),
      topDigits: [0, 1, 2],
      bottomDigits: [9, 8, 7],
      evenPercent: 50,
      oddPercent: 50,
      overPercent: 50,
      underPercent: 50,
      signal: "AI Waiting For Signal...",
      matchesProbability: 72,
      differsProbability: 81,
      aiConfidence: 89,
    };
  }

  const percentages = counts.map((c) => ((c / total) * 100).toFixed(1));

  const sorted = counts
    .map((count, index) => ({ count, index }))
    .sort((a, b) => b.count - a.count);

  const topDigits = [sorted[0].index, sorted[1].index, sorted[2].index];
  const bottomDigits = [sorted[9].index, sorted[8].index, sorted[7].index];

  let even = 0;
  let odd = 0;
  counts.forEach((count, index) => {
    if (index % 2 === 0) even += count;
    else odd += count;
  });
  const evenPercent = parseFloat(((even / total) * 100).toFixed(1));
  const oddPercent = parseFloat(((odd / total) * 100).toFixed(1));

  const over = counts.slice(6).reduce((a, b) => a + b, 0);
  const under = counts.slice(0, 6).reduce((a, b) => a + b, 0);
  const overPercent = parseFloat(((over / total) * 100).toFixed(1));
  const underPercent = parseFloat(((under / total) * 100).toFixed(1));

  const signal =
    evenPercent > oddPercent
      ? "AI SIGNAL → EVEN MARKET STRONG"
      : "AI SIGNAL → ODD MARKET STRONG";

  const topPct = parseFloat(percentages[topDigits[0]]);
  const matchesProbability = Math.min(95, Math.max(55, Math.round(topPct * 2.5 + 45)));
  const differsProbability = Math.min(95, Math.max(60, Math.round((100 - topPct) * 0.5 + 65)));
  const aiConfidence = Math.min(97, Math.max(70, Math.round((evenPercent + overPercent) / 2 + 30)));

  return {
    counts,
    total,
    lastDigit,
    percentages,
    topDigits,
    bottomDigits,
    evenPercent,
    oddPercent,
    overPercent,
    underPercent,
    signal,
    matchesProbability,
    differsProbability,
    aiConfidence,
  };
}

export default function Dashboard() {
  const [market, setMarket] = useState<Market>("Volatility 10");
  const [activeView, setActiveView] = useState<ActiveView>("Digits Analysis");
  const [counts, setCounts] = useState<number[]>(Array(10).fill(0));
  const [lastDigit, setLastDigit] = useState(0);
  const [flashKey, setFlashKey] = useState(0);
  const countsRef = useRef(counts);
  countsRef.current = counts;

  useEffect(() => {
    const interval = setInterval(() => {
      const digit = Math.floor(Math.random() * 10);
      const newCounts = [...countsRef.current];
      newCounts[digit]++;
      setCounts(newCounts);
      setLastDigit(digit);
      setFlashKey((k) => k + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const stats = computeStats(counts, lastDigit);

  return (
    <div className="flex min-h-screen" style={{ background: "#0b1220" }}>
      <Sidebar activeView={activeView} onViewChange={setActiveView} />
      <main className="flex-1 p-6 overflow-y-auto">
        {/* Topbar */}
        <div className="flex justify-between items-center mb-6">
          <select
            value={market}
            onChange={(e) => {
              setMarket(e.target.value as Market);
              setCounts(Array(10).fill(0));
            }}
            style={{
              background: "#1f2937",
              border: "none",
              color: "white",
              padding: "14px 18px",
              borderRadius: "12px",
              fontSize: "15px",
              cursor: "pointer",
              outline: "none",
            }}
          >
            {[
              "Volatility 10",
              "Volatility 25",
              "Volatility 50",
              "Volatility 75",
              "Volatility 100",
              "Boom 1000",
              "Crash 1000",
              "Jump 25",
              "Jump 50",
              "Jump 75",
              "Jump 100",
              "Step Index",
            ].map((m) => (
              <option key={m}>{m}</option>
            ))}
          </select>
          <div
            style={{
              background: "#16a34a",
              padding: "10px 20px",
              borderRadius: "50px",
              fontSize: "14px",
              fontWeight: 600,
              letterSpacing: "0.05em",
            }}
          >
            ● LIVE ANALYSIS
          </div>
        </div>

        {/* Cards Grid */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
            gap: "20px",
            marginBottom: "20px",
          }}
        >
          <DigitsDistribution stats={stats} flashKey={flashKey} />
          <EvenOddAnalysis stats={stats} />
          <OverUnderAnalysis stats={stats} />
        </div>

        <FooterPanels stats={stats} />
      </main>
    </div>
  );
}

