import type { DigitStats } from "../pages/Dashboard";

type Props = {
  stats: DigitStats;
  flashKey: number;
};

const digitColors: Record<string, string> = {
  green: "#14532d",
  blue: "#1d4ed8",
  lightblue: "#0369a1",
  red: "#991b1b",
  orange: "#ea580c",
  maroon: "#7f1d1d",
  normal: "#1f2937",
};

function getDigitColor(
  index: number,
  topDigits: number[],
  bottomDigits: number[]
): string {
  if (index === topDigits[0]) return digitColors.green;
  if (index === topDigits[1]) return digitColors.blue;
  if (index === topDigits[2]) return digitColors.lightblue;
  if (index === bottomDigits[0]) return digitColors.red;
  if (index === bottomDigits[1]) return digitColors.orange;
  if (index === bottomDigits[2]) return digitColors.maroon;
  return digitColors.normal;
}

function getLabel(index: number, topDigits: number[], bottomDigits: number[]) {
  if (index === topDigits[0]) return "HIGHEST";
  if (index === topDigits[1]) return "2ND";
  if (index === topDigits[2]) return "3RD";
  if (index === bottomDigits[0]) return "LOWEST";
  return null;
}

export default function DigitsDistribution({ stats, flashKey }: Props) {
  return (
    <div
      style={{
        background: "#111827",
        borderRadius: "24px",
        padding: "22px",
        border: "1px solid rgba(255,255,255,0.05)",
        boxShadow: "0 10px 25px rgba(0,0,0,0.25)",
      }}
    >
      <h3 style={{ marginBottom: "18px", fontSize: "18px", fontWeight: 600 }}>
        Digits Distribution
      </h3>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)",
          gap: "10px",
          marginBottom: "16px",
        }}
      >
        {stats.counts.map((_, i) => {
          const bg = getDigitColor(i, stats.topDigits, stats.bottomDigits);
          const label = getLabel(i, stats.topDigits, stats.bottomDigits);
          return (
            <div
              key={i}
              style={{
                height: "78px",
                borderRadius: "18px",
                background: bg,
                display: "flex",
                flexDirection: "column",
                justifyContent: "center",
                alignItems: "center",
                transition: "transform 0.2s",
                cursor: "default",
                position: "relative",
                border:
                  i === stats.lastDigit
                    ? "2px solid rgba(255,255,255,0.4)"
                    : "2px solid transparent",
              }}
              onMouseEnter={(e) =>
                ((e.currentTarget as HTMLDivElement).style.transform = "scale(1.07)")
              }
              onMouseLeave={(e) =>
                ((e.currentTarget as HTMLDivElement).style.transform = "scale(1)")
              }
            >
              {label && (
                <div
                  style={{
                    position: "absolute",
                    top: "4px",
                    fontSize: "8px",
                    fontWeight: 700,
                    color: "rgba(255,255,255,0.7)",
                    letterSpacing: "0.05em",
                  }}
                >
                  {label}
                </div>
              )}
              <div style={{ fontSize: "22px", fontWeight: 700 }}>{i}</div>
              <div style={{ fontSize: "12px", marginTop: "3px", color: "rgba(255,255,255,0.85)" }}>
                {stats.percentages[i]}%
              </div>
            </div>
          );
        })}
      </div>

      {/* Live tick */}
      <div
        key={flashKey}
        style={{
          background: "#0f172a",
          padding: "16px",
          borderRadius: "18px",
          textAlign: "center",
          fontSize: "20px",
          letterSpacing: "2px",
          fontWeight: 600,
          border: "1px solid rgba(255,255,255,0.06)",
          animation: "tick-flash 0.4s ease-out",
        }}
      >
        Last Digit:{" "}
        <span style={{ color: "#ff444f", fontSize: "28px" }}>{stats.lastDigit}</span>
        <span
          style={{
            marginLeft: "16px",
            fontSize: "13px",
            color: "rgba(255,255,255,0.4)",
            fontWeight: 400,
          }}
        >
          {stats.total} ticks
        </span>
      </div>
    </div>
  );
}

