import { useEffect, useRef, useState, useCallback } from "react";
import type { Market } from "../types";

const APP_ID = "1089";
const WS_URL = `wss://ws.binaryws.com/websockets/v3?app_id=${APP_ID}`;

function extractLastDigit(quote: number, pipSize: number): number {
  const factor = Math.pow(10, pipSize);
  return Math.floor(Math.round(quote * factor)) % 10;
}

export type DerivTickState = {
  connected: boolean;
  counts: number[];
  lastDigit: number;
  lastQuote: number;
  tickCount: number;
  error: string | null;
};

export function useDerivTicks(market: Market): DerivTickState {
  const wsRef = useRef<WebSocket | null>(null);
  const subscriptionIdRef = useRef<string | null>(null);
  const pipSizeRef = useRef<number>(3);
  const marketRef = useRef(market);
  marketRef.current = market;

  const [state, setState] = useState<DerivTickState>({
    connected: false,
    counts: Array(10).fill(0),
    lastDigit: 0,
    lastQuote: 0,
    tickCount: 0,
    error: null,
  });

  const countsRef = useRef<number[]>(Array(10).fill(0));

  const connect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
    }
    countsRef.current = Array(10).fill(0);
    setState({
      connected: false,
      counts: Array(10).fill(0),
      lastDigit: 0,
      lastQuote: 0,
      tickCount: 0,
      error: null,
    });

    const ws = new WebSocket(WS_URL);
    wsRef.current = ws;

    ws.onopen = () => {
      setState((s) => ({ ...s, connected: true, error: null }));
      ws.send(
        JSON.stringify({
          ticks: marketRef.current.symbol,
          subscribe: 1,
        })
      );
    };

    ws.onmessage = (evt) => {
      const data = JSON.parse(evt.data);

      if (data.error) {
        setState((s) => ({ ...s, error: data.error.message }));
        return;
      }

      if (data.msg_type === "tick") {
        const tick = data.tick;
        subscriptionIdRef.current = tick.id;
        pipSizeRef.current = tick.pip_size ?? 3;
        const digit = extractLastDigit(tick.quote, pipSizeRef.current);
        const newCounts = [...countsRef.current];
        newCounts[digit]++;
        countsRef.current = newCounts;
        setState((s) => ({
          ...s,
          connected: true,
          counts: [...newCounts],
          lastDigit: digit,
          lastQuote: tick.quote,
          tickCount: s.tickCount + 1,
          error: null,
        }));
      }
    };

    ws.onerror = () => {
      setState((s) => ({ ...s, connected: false, error: "Connection error" }));
    };

    ws.onclose = () => {
      setState((s) => ({ ...s, connected: false }));
      // Reconnect after 3s
      setTimeout(() => {
        if (wsRef.current === ws) {
          connect();
        }
      }, 3000);
    };
  }, []);

  useEffect(() => {
    connect();
    return () => {
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
        wsRef.current = null;
      }
    };
  }, [market.symbol, connect]);

  return state;
}

import { useState, useEffect, useRef, useCallback } from "react";
import type { Market, ScanResult } from "../types";
import { MARKETS } from "../types";

const APP_ID = "1089";
const WS_URL = `wss://ws.binaryws.com/websockets/v3?app_id=${APP_ID}`;
const SCAN_INTERVAL_MS = 60_000;

function extractLastDigit(quote: number, pipSize: number): number {
  const factor = Math.pow(10, pipSize);
  return Math.floor(Math.round(quote * factor)) % 10;
}

function analyzeMarket(market: Market, counts: number[], total: number): ScanResult {
  const percentages = counts.map((c) => ((c / Math.max(total, 1)) * 100).toFixed(1));

  const sorted = counts
    .map((count, index) => ({ count, index }))
    .sort((a, b) => b.count - a.count);

  const topDigits = [sorted[0].index, sorted[1].index, sorted[2].index];
  const bottomDigits = [sorted[9].index, sorted[8].index, sorted[7].index];

  // Score for Over N: target digits are > N. Lower combined% of target digits = higher score (reversal signal)
  const overScore: Record<number, number> = {};
  for (const barrier of [1, 2, 3, 4, 5, 6, 7, 8]) {
    const targetDigits = Array.from({ length: 9 }, (_, i) => i + 1).filter((d) => d > barrier);
    const targetCount = targetDigits.reduce((sum, d) => sum + counts[d], 0);
    const targetPct = total > 0 ? (targetCount / total) * 100 : 10;
    const expectedPct = (targetDigits.length / 10) * 100;
    // Score: how much BELOW expected the target digits are (higher = more "due")
    overScore[barrier] = expectedPct - targetPct;
  }

  // Score for Under N: target digits are < N. Lower combined% = higher score
  const underScore: Record<number, number> = {};
  for (const barrier of [1, 2, 3, 4, 5, 6, 7, 8]) {
    const targetDigits = Array.from({ length: 9 }, (_, i) => i).filter((d) => d < barrier);
    const targetCount = targetDigits.reduce((sum, d) => sum + counts[d], 0);
    const targetPct = total > 0 ? (targetCount / total) * 100 : 10;
    const expectedPct = (targetDigits.length / 10) * 100;
    underScore[barrier] = expectedPct - targetPct;
  }

  // Even/Odd scores
  const evenCount = [0, 2, 4, 6, 8].reduce((s, d) => s + counts[d], 0);
  const oddCount = [1, 3, 5, 7, 9].reduce((s, d) => s + counts[d], 0);
  const evenPct = total > 0 ? (evenCount / total) * 100 : 50;
  const oddPct = total > 0 ? (oddCount / total) * 100 : 50;
  const evenScore = 50 - evenPct; // higher = even digits are "due"
  const oddScore = 50 - oddPct;

  const godFor: string[] = [];
  if (evenScore > 5) godFor.push("EVEN");
  if (oddScore > 5) godFor.push("ODD");
  for (const [barrier, score] of Object.entries(overScore)) {
    if (score > 5) godFor.push(`OVER ${barrier}`);
  }
  for (const [barrier, score] of Object.entries(underScore)) {
    if (score > 5) godFor.push(`UNDER ${barrier}`);
  }

  return {
    market,
    counts,
    percentages,
    overScore,
    underScore,
    evenScore,
    oddScore,
    totalTicks: total,
    godFor,
  };
}

export function useMarketScanner(enabled: boolean) {
  const [results, setResults] = useState<ScanResult[]>([]);
  const [scanning, setScanning] = useState(false);
  const [lastScan, setLastScan] = useState<Date | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const pendingRef = useRef<Map<string, { counts: number[]; total: number; pipSize: number }>>(new Map());
  const completedRef = useRef<number>(0);
  const activeRef = useRef(false);

  const runScan = useCallback(() => {
    if (activeRef.current) return;
    activeRef.current = true;
    setScanning(true);
    pendingRef.current = new Map();
    completedRef.current = 0;

    // Scannable markets (exclude some that may timeout)
    const scanMarkets = MARKETS.filter((m) =>
      ["R_10", "R_25", "R_50", "R_75", "R_100", "1HZ10V", "1HZ25V", "1HZ50V", "1HZ75V", "1HZ100V"].includes(m.symbol)
    );

    for (const m of scanMarkets) {
      pendingRef.current.set(m.symbol, { counts: Array(10).fill(0), total: 0, pipSize: 3 });
    }

    if (wsRef.current) {
      wsRef.current.onclose = null;
      wsRef.current.close();
    }

    const ws = new WebSocket(WS_URL);
    wsRef.current = ws;

    ws.onopen = () => {
      // Send ticks_history requests for all markets
      for (const m of scanMarkets) {
        ws.send(
          JSON.stringify({
            ticks_history: m.symbol,
            end: "latest",
            count: 100,
            style: "ticks",
          })
        );
      }
    };

    ws.onmessage = (evt) => {
      const data = JSON.parse(evt.data);
      if (data.msg_type === "history" && data.history) {
        const symbol = data.echo_req?.ticks_history;
        const entry = pendingRef.current.get(symbol);
        if (!entry) return;

        const prices = data.history.prices as number[];
        const pipSize = 3; // default for synthetic indices
        entry.pipSize = pipSize;
        entry.counts = Array(10).fill(0);
        for (const price of prices) {
          const d = extractLastDigit(price, pipSize);
          entry.counts[d]++;
          entry.total++;
        }

        completedRef.current++;
        if (completedRef.current >= pendingRef.current.size) {
          // All done
          const scanResults: ScanResult[] = [];
          for (const [sym, dat] of pendingRef.current.entries()) {
            const market = MARKETS.find((m) => m.symbol === sym)!;
            if (market) {
              scanResults.push(analyzeMarket(market, dat.counts, dat.total));
            }
          }
          setResults(scanResults);
          setLastScan(new Date());
          setScanning(false);
          activeRef.current = false;
          ws.close();
        }
      }
    };

    ws.onerror = () => {
      setScanning(false);
      activeRef.current = false;
    };

    ws.onclose = () => {
      if (activeRef.current) {
        setScanning(false);
        activeRef.current = false;
      }
    };

    // Timeout after 20s
    setTimeout(() => {
      if (activeRef.current) {
        activeRef.current = false;
        setScanning(false);
        if (wsRef.current === ws) ws.close();
      }
    }, 20000);
  }, []);

  useEffect(() => {
    if (!enabled) return;
    runScan();
    const timer = setInterval(runScan, SCAN_INTERVAL_MS);
    return () => {
      clearInterval(timer);
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
      }
      activeRef.current = false;
    };
  }, [enabled, runScan]);

  return { results, scanning, lastScan, runScan };
}

import { useState, useRef, useCallback, useEffect } from "react";
import type { ScanResult } from "../types";
