const BARRIERS = [2, 3, 4, 5, 6, 7, 8];

type Props = {
  onSelectMarket?: (symbol: string) => void;
};

export default function MarketScanner({ onSelectMarket }: Props) {
  const [open, setOpen] = useState(false);
  const [enabled, setEnabled] = useState(false);
  const [activeTab, setActiveTab] = useState<"over" | "under" | "evenodd">("over");
  const [barrier, setBarrier] = useState(7);
  const [pos, setPos] = useState({ x: 20, y: 120 });
  const dragging = useRef(false);
  const dragOffset = useRef({ x: 0, y: 0 });
  const btnRef = useRef<HTMLDivElement>(null);

  const { results, scanning, lastScan, runScan } = useMarketScanner(enabled);

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    dragging.current = true;
    dragOffset.current = {
      x: e.clientX - pos.x,
      y: e.clientY - pos.y,
    };
    e.preventDefault();
  }, [pos]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      setPos({
        x: e.clientX - dragOffset.current.x,
        y: e.clientY - dragOffset.current.y,
      });
    };
    const onMouseUp = () => { dragging.current = false; };
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
    return () => {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    };
  }, []);

  const getRanked = (tab: "over" | "under" | "evenodd") => {
    if (tab === "evenodd") {
      return [...results].sort((a, b) => {
        const aScore = Math.max(a.evenScore, a.oddScore);
        const bScore = Math.max(b.evenScore, b.oddScore);
        return bScore - aScore;
      });
    }
    return [...results].sort((a, b) => {
      const aScore = tab === "over" ? (a.overScore[barrier] ?? 0) : (a.underScore[barrier] ?? 0);
      const bScore = tab === "over" ? (b.overScore[barrier] ?? 0) : (b.underScore[barrier] ?? 0);
      return bScore - aScore;
    });
  };

  const ranked = getRanked(activeTab);
  const godMarket = ranked[0];

  const getScoreLabel = (result: ScanResult) => {
    let score = 0;
    if (activeTab === "over") score = result.overScore[barrier] ?? 0;
    else if (activeTab === "under") score = result.underScore[barrier] ?? 0;
    else score = Math.max(result.evenScore, result.oddScore);
    return score.toFixed(1);
  };

  const getSignalStrength = (score: number) => {
    if (score > 10) return { label: "STRONG", color: "#22c55e" };
    if (score > 5) return { label: "GOOD", color: "#f59e0b" };
    if (score > 0) return { label: "WEAK", color: "#6b7280" };
    return { label: "NO SIGNAL", color: "#ef4444" };
  };

  const explainLogic = () => {
    if (activeTab === "over") {
      const count = 9 - barrier;
      return `Over ${barrier} wins when digit > ${barrier} (digits ${barrier + 1}–9, ${count} digits). GOD MARKET = digits ${barrier + 1}–9 are most UNDERREPRESENTED → due for reversal.`;
    }
    if (activeTab === "under") {
      return `Under ${barrier} wins when digit < ${barrier} (digits 0–${barrier - 1}). GOD MARKET = those digits are most UNDERREPRESENTED → due for reversal.`;
    }
    return "Even/Odd: GOD MARKET = whichever parity (even/odd) is most underrepresented relative to 50% → due for reversal.";
  };

  return (
    <div
      ref={btnRef}
      style={{
        position: "fixed",
        left: pos.x,
        top: pos.y,
        zIndex: 1000,
        userSelect: "none",
      }}
    >
      {/* Floating button */}
      <div
        onMouseDown={onMouseDown}
        onClick={() => {
          if (!dragging.current) {
            setOpen((o) => !o);
            if (!enabled) setEnabled(true);
          }
        }}
        style={{
          width: "60px",
