        <div style={{ fontSize: "20px" }}>🤖</div>
        <div style={{ fontSize: "8px", fontWeight: 700, color: "white", letterSpacing: "0.03em" }}>
          SCAN
        </div>
      </div>

      {/* Panel */}
      {open && (
        <div
