                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import type { DigitStats, ScanResult } from "../types";
import type { KimzMessage } from "../types";

type Props = {
  stats: DigitStats;
  marketLabel: string;
  scanResults: ScanResult[];
};

function generateId() {
  return Math.random().toString(36).slice(2);
}

function kimzRespond(input: string, stats: DigitStats, marketLabel: string, scanResults: ScanResult[]): string {
  const q = input.toLowerCase().trim();
  const top = stats.topDigits[0];
  const low = stats.bottomDigits[0];
  const total = stats.total;

  if (total < 10) {
    return "Not enough ticks yet to analyze. Please wait for more data to come in. I'll give you better signals once we have at least 50 ticks! 📊";
  }

  // Over/Under questions
  const overMatch = q.match(/over\s*(\d)/);
  const underMatch = q.match(/under\s*(\d)/);
  if (overMatch) {
    const barrier = parseInt(overMatch[1]);
    const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
    const targetPct = targetDigits.reduce((s, d) => s + (stats.counts[d] / total) * 100, 0);
    const expected = (targetDigits.length / 10) * 100;
    const edge = (expected - targetPct).toFixed(1);
    const best = scanResults.length > 0 ? [...scanResults].sort((a, b) => (b.overScore[barrier] ?? 0) - (a.overScore[barrier] ?? 0))[0] : null;
    return `📊 **Over ${barrier} Analysis on ${marketLabel}:**\n\nDigits ${barrier + 1}–9 have appeared ${targetPct.toFixed(1)}% of the time (expected ${expected.toFixed(0)}%).\n\nEdge signal: ${parseFloat(edge) > 0 ? `+${edge}% (those digits are DUE — good Over ${barrier} signal!)` : `${edge}% (those digits are OVER-represented — caution!)`}\n\nMost appearing: ${top} (${stats.percentages[top]}%), Least: ${low} (${stats.percentages[low]}%)${best ? `\n\n🏆 Best market for Over ${barrier}: **${best.market.label}** (use AI Scanner for full rankings)` : ""}`;
  }

  if (underMatch) {
    const barrier = parseInt(underMatch[1]);
    const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
    const targetPct = targetDigits.reduce((s, d) => s + (stats.counts[d] / total) * 100, 0);
    const expected = (targetDigits.length / 10) * 100;
    const edge = (expected - targetPct).toFixed(1);
    return `📊 **Under ${barrier} Analysis on ${marketLabel}:**\n\nDigits 0–${barrier - 1} have appeared ${targetPct.toFixed(1)}% of the time (expected ${expected.toFixed(0)}%).\n\nEdge signal: ${parseFloat(edge) > 0 ? `+${edge}% (those digits are DUE — good Under ${barrier} signal!)` : `${edge}% (those digits are OVER-represented — caution!)`}\n\nMost appearing: ${top}, Least: ${low}`;
  }

  // Even/Odd
  if (q.includes("even") || q.includes("odd")) {
    const signal = stats.evenPercent > stats.oddPercent ? "EVEN is dominating" : "ODD is dominating";
    const due = stats.evenPercent > stats.oddPercent ? "ODD digits are underrepresented" : "EVEN digits are underrepresented";
    return `📊 **Even/Odd on ${marketLabel}:**\n\nEven: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\n\n${signal}. Using reversal logic: ${due} and due for recovery.\n\nAI Signal: ${stats.signal}\n\n${stats.evenPercent > stats.oddPercent ? "Consider ODD trades (digits 1,3,5,7,9 are underrepresented)" : "Consider EVEN trades (digits 0,2,4,6,8 are underrepresented)"}`;
  }

  // Best market
  if (q.includes("best market") || q.includes("god market") || q.includes("which market")) {
    if (scanResults.length === 0) {
      return "Click the 🤖 AI Scanner button (draggable, on the left side) to scan all markets and find the GOD MARKET for your trade type!";
    }
    const bestOver7 = [...scanResults].sort((a, b) => (b.overScore[7] ?? 0) - (a.overScore[7] ?? 0))[0];
    const bestEven = [...scanResults].sort((a, b) => b.evenScore - a.evenScore)[0];
    return `🏆 **Current GOD Markets:**\n\n📈 Over 7: **${bestOver7?.market.label}** (score: +${bestOver7?.overScore[7]?.toFixed(1)})\n\n⚖️ Even: **${bestEven?.market.label}** (score: +${bestEven?.evenScore.toFixed(1)})\n\nUse the 🤖 AI Scanner button to see full rankings for all barriers!`;
  }

  // Confidence
  if (q.includes("confidence") || q.includes("ai confidence")) {
    return `🤖 **AI Confidence: ${stats.aiConfidence}%**\n\nThis measures how strongly the current digit distribution deviates from the theoretical 10% per digit. Higher = stronger statistical signal.\n\nCurrent distribution on ${marketLabel}: most appearing digit is ${top} at ${stats.percentages[top]}%, least is ${low} at ${stats.percentages[low]}%.`;
  }

  // Matches/Differs
  if (q.includes("match") || q.includes("differ")) {
    return `📊 **Matches/Differs on ${marketLabel}:**\n\nMatches probability: ${stats.matchesProbability}% (chance any specific digit repeats)\nDiffers probability: ${stats.differsProbability}%\n\nStatistically each digit has a 10% chance of appearing. Current dominant digit: ${top} (${stats.percentages[top]}%). If it's above 10%, the market slightly favors Differs.`;
  }

  // Last digit
  if (q.includes("last digit") || q.includes("current digit")) {
    return `🎯 Last digit on ${marketLabel}: **${stats.lastDigit}**\n\nRunning ${total} ticks. Digit ${top} is the most frequent at ${stats.percentages[top]}%. Digit ${low} is the rarest at ${stats.percentages[low]}%.`;
  }

  // How it works
  if (q.includes("how") && (q.includes("work") || q.includes("scanner"))) {
    return `🤖 **How the AI Scanner works:**\n\n1. Fetches 100 recent ticks for each Volatility market\n2. Analyzes digit distribution (each digit should appear ~10%)\n3. Applies reversal logic: if target digits are UNDERREPRESENTED, they're "due"\n4. Scores each market — higher score = stronger reversal signal\n5. The GOD MARKET has the highest score for your selected trade type\n\n⚠️ This is statistical analysis for educational purposes only.`;
  }

  // Ticks count
  if (q.includes("tick") || q.includes("sample") || q.includes("data")) {
    return `📡 **Live data on ${marketLabel}:**\n\nConnected to Deriv WebSocket API — receiving real-time ticks.\nTotal ticks analyzed: **${total}**\n\nDistribution:\n${stats.counts.map((c, i) => `  Digit ${i}: ${stats.percentages[i]}%`).join("\n")}`;
  }

  // Greeting
  if (q.match(/^(hi|hello|hey|sup|yo)/)) {
    return `👋 Hey! I'm **Kimz Analysis** — your AI trading assistant powered by live Deriv data!\n\nI can help you with:\n• Over/Under analysis (e.g., "analyze over 7")\n• Even/Odd signals\n• Best market for your trade type\n• Matches/Differs probability\n• Understanding the AI scanner\n\nWhat would you like to know?`;
  }

  // Default
  const topPct = stats.percentages[top];
  const lowPct = stats.percentages[low];
  return `📊 **${marketLabel} Quick Summary** (${total} ticks):\n\n🔥 Most common: Digit **${top}** (${topPct}%)\n❄️ Least common: Digit **${low}** (${lowPct}%)\n\n⚖️ Even: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\nAI Signal: **${stats.signal}**\n\nAsk me about "over 7", "even analysis", "best market", or "how does the scanner work"!`;
}

