import { useState } from "react";
import type { DigitStats } from "../types";

type Props = { stats: DigitStats };

const BARRIERS = [1, 2, 3, 4, 5, 6, 7, 8];

function getOverUnderExplain(barrier: number, stats: DigitStats) {
  const targetOver = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
  const targetUnder = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
  const total = Math.max(stats.total, 1);

  const overCount = targetOver.reduce((s, d) => s + stats.counts[d], 0);
  const underCount = targetUnder.reduce((s, d) => s + stats.counts[d], 0);
  const overPct = ((overCount / total) * 100).toFixed(1);
  const underPct = ((underCount / total) * 100).toFixed(1);
  const expectedOver = ((targetOver.length / 10) * 100).toFixed(0);
  const expectedUnder = ((targetUnder.length / 10) * 100).toFixed(0);
  const overEdge = (parseFloat(expectedOver) - parseFloat(overPct)).toFixed(1);
  const underEdge = (parseFloat(expectedUnder) - parseFloat(underPct)).toFixed(1);

  return { overPct, underPct, expectedOver, expectedUnder, overEdge, underEdge, targetOver, targetUnder };
}

