import { useState, useEffect, useRef, useCallback } from "react";
import type { Market, ScanResult } from "../types";
import { MARKETS } from "../types";

const APP_ID = "1089";
const WS_URL = `wss://ws.binaryws.com/websockets/v3?app_id=${APP_ID}`;
const SCAN_INTERVAL_MS = 60_000;

function extractLastDigit(quote: number, pipSize: number): number {
  const factor = Math.pow(10, pipSize);
  return Math.floor(Math.round(quote * factor)) % 10;
}

/**
 * Scoring rules per barrier (reversal vs trend logic):
 *
 * Over 7 / Over 8  → REVERSAL: digits ABOVE barrier are underrepresented (due)
 *                    Score = expected%(digits>barrier) − actual%
 *
 * Over 5 / Over 6  → REVERSAL: same (digits above barrier underrepresented)
 *
 * Over 3 / Over 4  → TREND: digits 0,1,2 are the LEAST appearing (most digits >3)
 *                    Score = expected%(0,1,2=30%) − actual%(0,1,2)
 *                    Higher = 0-2 are rarer = trend above 3 is strong
 *
 * Over 1 / Over 2  → REVERSAL (default)
 *
 * Under 5 / Under 6 → TREND: digits 0,1,2,3 are MOST appearing, digits >4 are least
 *                    Score = actual%(0,1,2,3) − expected%(40%)
 *
 * Under 1-4 / Under 7-8 → REVERSAL: digits BELOW barrier underrepresented (due)
 *                    Score = expected%(digits<barrier) − actual%
 */
function scoreOver(barrier: number, counts: number[], total: number): number {
  if (total === 0) return 0;

  if (barrier === 3 || barrier === 4) {
    // TREND: digits 0,1,2 should be least appearing
    const lowDigits = [0, 1, 2];
    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    const lowPct = (lowCount / total) * 100;
    const expectedPct = 30; // 3 digits × 10%
    return expectedPct - lowPct; // higher = 0-2 are rarer = upward trend
  }

  // Default REVERSAL: digits above barrier should be underrepresented (due)
  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
  const targetPct = (targetCount / total) * 100;
  const expectedPct = (targetDigits.length / 10) * 100;
  return expectedPct - targetPct;
}

function scoreUnder(barrier: number, counts: number[], total: number): number {
  if (total === 0) return 0;

  if (barrier === 5 || barrier === 6) {
    // TREND: digits 0,1,2,3 are MOST appearing AND digits >4 are least
    const lowDigits = [0, 1, 2, 3];
    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    const lowPct = (lowCount / total) * 100;
    const expectedPct = 40; // 4 digits × 10%
    return lowPct - expectedPct; // higher = 0-3 appear more than expected = downward trend
  }

  // Default REVERSAL: digits below barrier should be underrepresented (due)
  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
  const targetPct = (targetCount / total) * 100;
  const expectedPct = (targetDigits.length / 10) * 100;
  return expectedPct - targetPct;
}

function analyzeMarket(market: Market, counts: number[], total: number): ScanResult {
  const percentages = counts.map((c) => ((c / Math.max(total, 1)) * 100).toFixed(1));

  const overScore: Record<number, number> = {};
  const underScore: Record<number, number> = {};

  for (const barrier of [1, 2, 3, 4, 5, 6, 7, 8]) {
    overScore[barrier] = scoreOver(barrier, counts, total);
    underScore[barrier] = scoreUnder(barrier, counts, total);
  }

  const evenCount = [0, 2, 4, 6, 8].reduce((s, d) => s + counts[d], 0);
  const oddCount = [1, 3, 5, 7, 9].reduce((s, d) => s + counts[d], 0);
  const evenPct = total > 0 ? (evenCount / total) * 100 : 50;
  const oddPct = total > 0 ? (oddCount / total) * 100 : 50;
  const evenScore = 50 - evenPct;
  const oddScore = 50 - oddPct;

  const godFor: string[] = [];
  if (evenScore > 5) godFor.push("EVEN");
  if (oddScore > 5) godFor.push("ODD");
  for (const [b, score] of Object.entries(overScore)) {
    if (score > 5) godFor.push(`OVER ${b}`);
  }
  for (const [b, score] of Object.entries(underScore)) {
    if (score > 5) godFor.push(`UNDER ${b}`);
  }

  return {
    market,
    counts,
    percentages,
    overScore,
    underScore,
    evenScore,
    oddScore,
    totalTicks: total,
    godFor,
  };
}

export function useMarketScanner(enabled: boolean) {
  const [results, setResults] = useState<ScanResult[]>([]);
  const [scanning, setScanning] = useState(false);
  const [lastScan, setLastScan] = useState<Date | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const pendingRef = useRef<Map<string, { counts: number[]; total: number }>>(new Map());
  const completedRef = useRef<number>(0);
  const activeRef = useRef(false);

  const runScan = useCallback(() => {
    if (activeRef.current) return;
    activeRef.current = true;
    setScanning(true);
    pendingRef.current = new Map();
    completedRef.current = 0;

    const scanMarkets = MARKETS.filter((m) =>
      ["R_10", "R_25", "R_50", "R_75", "R_100", "1HZ10V", "1HZ25V", "1HZ50V", "1HZ75V", "1HZ100V"].includes(m.symbol)
    );

    for (const m of scanMarkets) {
      pendingRef.current.set(m.symbol, { counts: Array(10).fill(0), total: 0 });
    }

    if (wsRef.current) {
      wsRef.current.onclose = null;
      wsRef.current.close();
    }

    const ws = new WebSocket(WS_URL);
    wsRef.current = ws;

    ws.onopen = () => {
      for (const m of scanMarkets) {
        ws.send(
          JSON.stringify({
            ticks_history: m.symbol,
            end: "latest",
            count: 100,
            style: "ticks",
          })
        );
      }
    };

    ws.onmessage = (evt) => {
      const data = JSON.parse(evt.data);
      if (data.msg_type === "history" && data.history) {
        const symbol = data.echo_req?.ticks_history;
        const entry = pendingRef.current.get(symbol);
        if (!entry) return;

        const prices = data.history.prices as number[];
        entry.counts = Array(10).fill(0);
        for (const price of prices) {
          const d = extractLastDigit(price, 3);
          entry.counts[d]++;
          entry.total++;
        }

        completedRef.current++;
        if (completedRef.current >= pendingRef.current.size) {
          const scanResults: ScanResult[] = [];
          for (const [sym, dat] of pendingRef.current.entries()) {
            const market = MARKETS.find((m) => m.symbol === sym)!;
            if (market) scanResults.push(analyzeMarket(market, dat.counts, dat.total));
          }
          setResults(scanResults);
          setLastScan(new Date());
          setScanning(false);
          activeRef.current = false;
          ws.close();
        }
      }
    };

    ws.onerror = () => {
      setScanning(false);
      activeRef.current = false;
    };

    ws.onclose = () => {
      if (activeRef.current) {
        setScanning(false);
        activeRef.current = false;
      }
    };

    setTimeout(() => {
      if (activeRef.current) {
        activeRef.current = false;
        setScanning(false);
        if (wsRef.current === ws) ws.close();
      }
    }, 20000);
  }, []);

  useEffect(() => {
    if (!enabled) return;
    runScan();
    const timer = setInterval(runScan, SCAN_INTERVAL_MS);
    return () => {
      clearInterval(timer);
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
      }
      activeRef.current = false;
    };
  }, [enabled, runScan]);

  return { results, scanning, lastScan, runScan };
}

import { useState } from "react";
import type { DigitStats } from "../types";

type Props = { stats: DigitStats };

const BARRIERS = [1, 2, 3, 4, 5, 6, 7, 8];

/**
 * Per-barrier GOD MARKET logic:
 *
 * Over 7/8  → REVERSAL: digits above barrier are underrepresented (due)
 * Over 5/6  → REVERSAL: same
 * Over 3/4  → TREND: digits 0,1,2 are LEAST appearing (most digits fall above 3)
 * Over 1/2  → REVERSAL
 *
 * Under 5/6 → TREND: digits 0,1,2,3 are MOST appearing; digits above 4 are LEAST
 * Under 1-4 / 7-8 → REVERSAL
 */
function getLogicType(tradeType: "over" | "under", barrier: number): "reversal" | "trend-up" | "trend-down" {
  if (tradeType === "over" && (barrier === 3 || barrier === 4)) return "trend-up";
  if (tradeType === "under" && (barrier === 5 || barrier === 6)) return "trend-down";
  return "reversal";
}

function computeMetrics(
  tradeType: "over" | "under",
  barrier: number,
  stats: DigitStats
) {
  const total = Math.max(stats.total, 1);
  const logic = getLogicType(tradeType, barrier);

  if (tradeType === "over") {
    if (logic === "trend-up") {
      // Over 3/4: least appearing = digits 0,1,2
      const lowDigits = [0, 1, 2];
      const lowCount = lowDigits.reduce((s, d) => s + stats.counts[d], 0);
      const lowPct = ((lowCount / total) * 100).toFixed(1);
      const edge = (30 - parseFloat(lowPct)).toFixed(1); // positive = 0-2 are rare = upward trend
      const targetPct = ((stats.counts.slice(barrier + 1).reduce((a, b) => a + b, 0) / total) * 100).toFixed(1);
      const conditionMet = parseFloat(edge) > 0;
      return { lowPct, edge, conditionMet, targetPct, logic };
    }
    // REVERSAL: digits above barrier underrepresented
    const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
    const targetCount = targetDigits.reduce((s, d) => s + stats.counts[d], 0);
    const targetPct = ((targetCount / total) * 100).toFixed(1);
    const expected = ((targetDigits.length / 10) * 100).toFixed(0);
    const edge = (parseFloat(expected) - parseFloat(targetPct)).toFixed(1);
    const conditionMet = parseFloat(edge) > 0;
    return { targetPct, expected, edge, conditionMet, logic };
  } else {
    if (logic === "trend-down") {
      // Under 5/6: digits 0,1,2,3 most appearing; digits >4 least
      const lowDigits = [0, 1, 2, 3];
      const highDigits = [5, 6, 7, 8, 9];
      const lowCount = lowDigits.reduce((s, d) => s + stats.counts[d], 0);
      const highCount = highDigits.reduce((s, d) => s + stats.counts[d], 0);
      const lowPct = ((lowCount / total) * 100).toFixed(1);
      const highPct = ((highCount / total) * 100).toFixed(1);
      const edgeLow = (parseFloat(lowPct) - 40).toFixed(1); // positive = 0-3 appear more
      const edgeHigh = (50 - parseFloat(highPct)).toFixed(1); // positive = 5-9 appear less
      const conditionMet = parseFloat(edgeLow) > 0 && parseFloat(edgeHigh) > 0;
      return { lowPct, highPct, edgeLow, edgeHigh, conditionMet, logic };
    }
    // REVERSAL: digits below barrier underrepresented
    const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
    const targetCount = targetDigits.reduce((s, d) => s + stats.counts[d], 0);
    const targetPct = ((targetCount / total) * 100).toFixed(1);
    const expected = ((targetDigits.length / 10) * 100).toFixed(0);
    const edge = (parseFloat(expected) - parseFloat(targetPct)).toFixed(1);
    const conditionMet = parseFloat(edge) > 0;
    return { targetPct, expected, edge, conditionMet, logic };
  }
}

function LogicBadge({ type }: { type: "reversal" | "trend-up" | "trend-down" }) {
  const map = {
    reversal: { label: "REVERSAL", color: "#8b5cf6", bg: "rgba(139,92,246,0.15)" },
    "trend-up": { label: "TREND ↑", color: "#22c55e", bg: "rgba(34,197,94,0.15)" },
    "trend-down": { label: "TREND ↓", color: "#3b82f6", bg: "rgba(59,130,246,0.15)" },
  };
  const s = map[type];
  return (
    <span
      style={{
        fontSize: "10px",
        fontWeight: 700,
        color: s.color,
        background: s.bg,
        padding: "2px 7px",
        borderRadius: "6px",
        border: `1px solid ${s.color}44`,
        letterSpacing: "0.05em",
      }}
    >
      {s.label}
    </span>
  );
}

export default function OverUnderAnalysis({ stats }: Props) {
  const [barrier, setBarrier] = useState(5);
  const [activeView, setActiveView] = useState<"chart" | "explain">("chart");

  const overMetrics = computeMetrics("over", barrier, stats);
  const underMetrics = computeMetrics("under", barrier, stats);

  // Determine which signal is stronger for the recommendation
  const overEdgeNum = parseFloat(overMetrics.edge ?? overMetrics.edgeLow ?? "0");
  const underEdgeNum = parseFloat(underMetrics.edge ?? underMetrics.edgeLow ?? "0");
  const overValid = overMetrics.conditionMet;
  const underValid = underMetrics.conditionMet;

  const recommendation =
    overValid && overEdgeNum >= underEdgeNum
      ? { label: `OVER ${barrier} SIGNAL`, color: "#3b82f6", desc: getOverDesc(barrier, overMetrics) }
      : underValid
      ? { label: `UNDER ${barrier} SIGNAL`, color: "#a855f7", desc: getUnderDesc(barrier, underMetrics) }
      : { label: "NO CLEAR SIGNAL", color: "#6b7280", desc: "Conditions not met on current market" };

  function getOverDesc(b: number, m: typeof overMetrics): string {
    if (m.logic === "trend-up") return `Digits 0,1,2 rare (${m.lowPct}%) — most digits above ${b}`;
    return `Digits ${b + 1}–9 underrepresented at ${m.targetPct}% (expected ~${m.expected}%)`;
  }

  function getUnderDesc(b: number, m: typeof underMetrics): string {
    if (m.logic === "trend-down") return `Digits 0–3 dominating (${m.lowPct}%), digits 5–9 rare (${m.highPct}%)`;
    return `Digits 0–${b - 1} underrepresented at ${m.targetPct}% (expected ~${m.expected}%)`;
  }

  return (
    <div
      style={{
        background: "#111827",
        borderRadius: "24px",
        padding: "22px",
        border: "1px solid rgba(255,255,255,0.05)",
        boxShadow: "0 10px 25px rgba(0,0,0,0.25)",
        display: "flex",
        flexDirection: "column",
