import { useState, useRef, useEffect, useCallback } from "react";
import type { DigitStats, ScanResult } from "../types";
import type { KimzMessage } from "../types";

type Props = {
  stats: DigitStats;
  marketLabel: string;
  scanResults: ScanResult[];
};

function generateId() {
  return Math.random().toString(36).slice(2);
}

function getLogicType(tradeType: "over" | "under", barrier: number): "reversal" | "trend-up" | "trend-down" {
  if (tradeType === "over" && (barrier === 3 || barrier === 4)) return "trend-up";
  if (tradeType === "under" && (barrier === 5 || barrier === 6)) return "trend-down";
  return "reversal";
}

function describeOverLogic(barrier: number): string {
  const logic = getLogicType("over", barrier);
  if (logic === "trend-up") {
    return `Over ${barrier} uses TREND logic: digits 0,1,2 must be the LEAST appearing. This means most digits are falling above ${barrier} — confirming a strong upward bias.`;
  }
  return `Over ${barrier} uses REVERSAL logic: digits ${barrier + 1}–9 must be UNDERREPRESENTED (below expected ${(9 - barrier) * 10}%). They are "due" for a reversal upward.`;
}

function describeUnderLogic(barrier: number): string {
  const logic = getLogicType("under", barrier);
  if (logic === "trend-down") {
    return `Under ${barrier} uses TREND logic: digits 0,1,2,3 must be the MOST appearing AND digits 5–9 must be the LEAST appearing. This confirms a strong downward bias.`;
  }
  return `Under ${barrier} uses REVERSAL logic: digits 0–${barrier - 1} must be UNDERREPRESENTED (below expected ${barrier * 10}%). They are "due" for a reversal downward.`;
}

function assessOverCondition(barrier: number, stats: DigitStats): { met: boolean; detail: string } {
  const total = Math.max(stats.total, 1);
  const logic = getLogicType("over", barrier);
  if (logic === "trend-up") {
    const lowCount = [0, 1, 2].reduce((s, d) => s + stats.counts[d], 0);
    const lowPct = ((lowCount / total) * 100).toFixed(1);
    const met = parseFloat(lowPct) < 30;
    return { met, detail: `Digits 0,1,2 = ${lowPct}% (need <30% for GOD signal)` };
  }
  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
  const targetCount = targetDigits.reduce((s, d) => s + stats.counts[d], 0);
  const targetPct = ((targetCount / total) * 100).toFixed(1);
  const expected = ((targetDigits.length / 10) * 100).toFixed(0);
  const met = parseFloat(targetPct) < parseFloat(expected);
  return { met, detail: `Digits ${barrier + 1}–9 = ${targetPct}% vs expected ${expected}%` };
}

function assessUnderCondition(barrier: number, stats: DigitStats): { met: boolean; detail: string } {
  const total = Math.max(stats.total, 1);
  const logic = getLogicType("under", barrier);
  if (logic === "trend-down") {
    const lowCount = [0, 1, 2, 3].reduce((s, d) => s + stats.counts[d], 0);
    const highCount = [5, 6, 7, 8, 9].reduce((s, d) => s + stats.counts[d], 0);
    const lowPct = ((lowCount / total) * 100).toFixed(1);
    const highPct = ((highCount / total) * 100).toFixed(1);
    const met = parseFloat(lowPct) > 40 && parseFloat(highPct) < 50;
    return { met, detail: `Digits 0–3 = ${lowPct}% (need >40%) | Digits 5–9 = ${highPct}% (need <50%)` };
  }
  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
  const targetCount = targetDigits.reduce((s, d) => s + stats.counts[d], 0);
  const targetPct = ((targetCount / total) * 100).toFixed(1);
  const expected = ((targetDigits.length / 10) * 100).toFixed(0);
  const met = parseFloat(targetPct) < parseFloat(expected);
  return { met, detail: `Digits 0–${barrier - 1} = ${targetPct}% vs expected ${expected}%` };
}

function kimzRespond(input: string, stats: DigitStats, marketLabel: string, scanResults: ScanResult[]): string {
  const q = input.toLowerCase().trim();
  const top = stats.topDigits[0];
  const low = stats.bottomDigits[0];
  const total = stats.total;

  if (total < 10) {
    return "Not enough ticks yet. Please wait for at least 20 ticks so I can give you meaningful signals! 📊";
  }

  // Over N questions
  const overMatch = q.match(/over\s*(\d)/);
  if (overMatch) {
    const barrier = parseInt(overMatch[1]);
    const logic = getLogicType("over", barrier);
    const { met, detail } = assessOverCondition(barrier, stats);
    const logicDesc = describeOverLogic(barrier);
    const best = scanResults.length > 0
      ? [...scanResults].sort((a, b) => (b.overScore[barrier] ?? 0) - (a.overScore[barrier] ?? 0))[0]
      : null;
    return `📊 **Over ${barrier} Analysis — ${marketLabel}**\n\nLogic: ${logicDesc}\n\nCurrent status:\n${detail}\n\nSignal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met — avoid"}\n\nMost appearing: digit ${top} (${stats.percentages[top]}%) | Least: digit ${low} (${stats.percentages[low]}%)${best ? `\n\n🏆 Best market for Over ${barrier}: **${best.market.label}** (use AI Scanner for full list)` : ""}`;
  }

  // Under N questions
  const underMatch = q.match(/under\s*(\d)/);
  if (underMatch) {
    const barrier = parseInt(underMatch[1]);
    const logic = getLogicType("under", barrier);
    const { met, detail } = assessUnderCondition(barrier, stats);
    const logicDesc = describeUnderLogic(barrier);
    const best = scanResults.length > 0
      ? [...scanResults].sort((a, b) => (b.underScore[barrier] ?? 0) - (a.underScore[barrier] ?? 0))[0]
      : null;
    return `📊 **Under ${barrier} Analysis — ${marketLabel}**\n\nLogic: ${logicDesc}\n\nCurrent status:\n${detail}\n\nSignal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met — avoid"}\n\nMost appearing: digit ${top} | Least: digit ${low}${best ? `\n\n🏆 Best market for Under ${barrier}: **${best.market.label}**` : ""}`;
  }

  // Even/Odd
  if (q.includes("even") || q.includes("odd")) {
    const due = stats.evenPercent > stats.oddPercent ? "ODD" : "EVEN";
    const dueDigits = due === "ODD" ? "1,3,5,7,9" : "0,2,4,6,8";
    const duePct = due === "ODD" ? stats.oddPercent : stats.evenPercent;
    return `📊 **Even/Odd — ${marketLabel}**\n\nEven: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\n\nReversal signal: **${due}** digits (${dueDigits}) are underrepresented at ${duePct}% — due for recovery.\n\nAI Signal: ${stats.signal}\n\nConsider trading ${due} on this market.`;
  }

  // Best market / god market
  if (q.includes("best market") || q.includes("god market") || q.includes("which market")) {
    if (scanResults.length === 0) {
      return "Tap the 🤖 SCAN button (draggable, top-left) to scan all markets and find the GOD MARKET for each trade type!";
    }
    const bestOver7 = [...scanResults].sort((a, b) => (b.overScore[7] ?? 0) - (a.overScore[7] ?? 0))[0];
    const bestOver4 = [...scanResults].sort((a, b) => (b.overScore[4] ?? 0) - (a.overScore[4] ?? 0))[0];
    const bestUnder5 = [...scanResults].sort((a, b) => (b.underScore[5] ?? 0) - (a.underScore[5] ?? 0))[0];
    const bestEven = [...scanResults].sort((a, b) => b.evenScore - a.evenScore)[0];
    return `🏆 **Current GOD Markets (${scanResults.length} scanned):**\n\nOver 7 (reversal): **${bestOver7?.market.label}**\nOver 4 (trend ↑): **${bestOver4?.market.label}**\nUnder 5 (trend ↓): **${bestUnder5?.market.label}**\nEven: **${bestEven?.market.label}**\n\nOpen the 🤖 AI Scanner for full rankings by barrier!`;
  }

  // Logic explanation
  if (q.includes("logic") || q.includes("how") && (q.includes("work") || q.includes("scanner"))) {
    return `🤖 **Kimz Signal Logic:**\n\n**Over 3/4 → TREND**: digits 0,1,2 must be LEAST appearing. Most digits fall above ${3} — confirms upward bias. Trade the trend.\n\n**Over 5–8 → REVERSAL**: digits above barrier must be underrepresented (they're "due"). Bet on reversal.\n\n**Under 5/6 → TREND**: digits 0–3 most appearing AND digits 5–9 least appearing. Strong downward bias.\n\n**Under others → REVERSAL**: digits below barrier underrepresented and due.\n\n⚠️ Educational only — not financial advice.`;
  }

  // Digit distribution
  if (q.includes("digit") || q.includes("distribution") || q.includes("count")) {
    return `📡 **Digit Distribution — ${marketLabel} (${total} ticks):**\n\n${stats.counts.map((c, i) => `Digit ${i}: ${stats.percentages[i]}% ${i === top ? "🔥 HIGHEST" : i === low ? "❄️ LOWEST" : ""}`).join("\n")}`;
  }

  // Greeting
  if (q.match(/^(hi|hello|hey|sup|yo)/)) {
    return `👋 Hey! I'm **Kimz Analysis** — live-connected to ${marketLabel}.\n\nI know the exact signal logic:\n• Over 3/4: TREND (digits 0,1,2 must be rare)\n• Over 5–8: REVERSAL (target digits underrepresented)\n• Under 5/6: TREND (digits 0–3 dominating)\n• Under others: REVERSAL\n\nAsk me: "analyze over 4", "under 5 signal", "best market?", or "explain logic"!`;
  }

  // Default summary
  return `📊 **${marketLabel} Summary** (${total} ticks)\n\n🔥 Most: Digit **${top}** (${stats.percentages[top]}%)\n❄️ Least: Digit **${low}** (${stats.percentages[low]}%)\n\n⚖️ Even: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\n${stats.signal}\n\nTry: "over 3", "under 5", "over 7", "best market?", or "explain logic"`;
}

export default function KimzAnalysis({ stats, marketLabel, scanResults }: Props) {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState<KimzMessage[]>([
    {
      id: generateId(),
      role: "kimz",
      text: "👋 Hi! I'm **Kimz Analysis** — I know your exact trade logic:\n\n• **Over 3/4**: TREND (digits 0,1,2 must be rare)\n• **Over 5–8**: REVERSAL (target digits due)\n• **Under 5/6**: TREND (digits 0–3 dominating, 5–9 rare)\n• **Under others**: REVERSAL\n\nAsk me anything!",
      ts: Date.now(),
    },
  ]);
  const [input, setInput] = useState("");
  const [pos, setPos] = useState({ x: 20, y: 200 });
  const dragging = useRef(false);
  const dragOffset = useRef({ x: 0, y: 0 });
  const bottomRef = useRef<HTMLDivElement>(null);

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    dragging.current = true;
    dragOffset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.preventDefault();
  }, [pos]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      setPos({ x: e.clientX - dragOffset.current.x, y: e.clientY - dragOffset.current.y });
    };
    const onMouseUp = () => { dragging.current = false; };
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
    return () => {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    };
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = (text?: string) => {
    const t = (text ?? input).trim();
    if (!t) return;
    const userMsg: KimzMessage = { id: generateId(), role: "user", text: t, ts: Date.now() };
    const reply: KimzMessage = { id: generateId(), role: "kimz", text: kimzRespond(t, stats, marketLabel, scanResults), ts: Date.now() };
    setMessages((m) => [...m, userMsg, reply]);
    setInput("");
  };

  const formatText = (text: string) =>
    text.split("\n").map((line, i) => (
      <div
        key={i}
        dangerouslySetInnerHTML={{ __html: line.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>") || "&nbsp;" }}
        style={{ lineHeight: 1.5 }}
      />
    ));

  const suggestions = ["analyze over 4", "under 5 signal", "over 7", "best market?", "explain logic"];

  return (
    <div style={{ position: "fixed", left: pos.x, top: pos.y, zIndex: 999, userSelect: "none" }}>
      {/* Floating button */}
      <div
        onMouseDown={onMouseDown}
        onClick={() => setOpen((o) => !o)}
        style={{
          width: "60px",
          height: "60px",
          borderRadius: "50%",
          background: "linear-gradient(135deg, #f59e0b, #ef4444)",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          cursor: "grab",
          boxShadow: "0 4px 20px rgba(245,158,11,0.5)",
          border: "2px solid rgba(255,255,255,0.15)",
          marginTop: "10px",
        }}
      >
        <div style={{ fontSize: "20px" }}>💬</div>
        <div style={{ fontSize: "8px", fontWeight: 700, color: "white" }}>KIMZ</div>
      </div>

      {open && (
        <div
          style={{
            position: "absolute",
            left: "70px",
            top: "0",
            width: "360px",
            background: "#111827",
            borderRadius: "20px",
            border: "1px solid rgba(245,158,11,0.3)",
            boxShadow: "0 20px 40px rgba(0,0,0,0.5)",
            display: "flex",
            flexDirection: "column",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              padding: "14px 18px",
              background: "linear-gradient(135deg, #f59e0b, #ef4444)",
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <div>
              <div style={{ fontWeight: 700, fontSize: "15px" }}>💬 Kimz Analysis AI</div>
              <div style={{ fontSize: "11px", opacity: 0.85 }}>
                {stats.total} ticks · {marketLabel}
              </div>
            </div>
            <button
              onClick={() => setOpen(false)}
              style={{ background: "rgba(0,0,0,0.2)", border: "none", color: "white", width: "28px", height: "28px", borderRadius: "50%", cursor: "pointer", fontSize: "16px" }}
            >
              ×
            </button>
          </div>

          {/* Suggestions */}
          <div style={{ display: "flex", gap: "5px", padding: "8px 10px", flexWrap: "wrap", borderBottom: "1px solid rgba(255,255,255,0.06)", background: "rgba(245,158,11,0.04)" }}>
            {suggestions.map((q) => (
              <button
                key={q}
                onClick={() => sendMessage(q)}
                style={{ background: "#1f2937", border: "1px solid rgba(245,158,11,0.2)", color: "rgba(255,255,255,0.7)", padding: "4px 9px", borderRadius: "20px", cursor: "pointer", fontSize: "11px" }}
              >
                {q}
              </button>
            ))}
          </div>

          {/* Messages */}
          <div style={{ height: "320px", overflowY: "auto", padding: "12px", display: "flex", flexDirection: "column", gap: "10px" }}>
            {messages.map((msg) => (
              <div key={msg.id} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start" }}>
                <div
                  style={{
                    maxWidth: "85%",
                    padding: "10px 14px",
                    borderRadius: msg.role === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                    background: msg.role === "user" ? "linear-gradient(135deg, #f59e0b, #ef4444)" : "#1f2937",
                    fontSize: "12px",
                    lineHeight: 1.6,
                    color: "white",
                    border: msg.role === "kimz" ? "1px solid rgba(255,255,255,0.06)" : "none",
