                >
                  {formatText(msg.text)}
                </div>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>

          {/* Input */}
          <div style={{ display: "flex", gap: "8px", padding: "10px 12px", borderTop: "1px solid rgba(255,255,255,0.08)", background: "#0f172a" }}>
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
              placeholder="Ask Kimz anything..."
              style={{ flex: 1, background: "#1f2937", border: "1px solid rgba(255,255,255,0.08)", borderRadius: "12px", padding: "8px 14px", color: "white", fontSize: "13px", outline: "none" }}
            />
            <button
              onClick={() => sendMessage()}
              style={{ background: "linear-gradient(135deg, #f59e0b, #ef4444)", border: "none", borderRadius: "12px", padding: "8px 14px", color: "white", cursor: "pointer", fontWeight: 700, fontSize: "13px" }}
            >
              ↑
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useRef, useCallback, useEffect } from "react";
import type { ScanResult } from "../types";
import { useMarketScanner } from "../hooks/useMarketScanner";

const BARRIERS = [2, 3, 4, 5, 6, 7, 8];

type Props = {
  onSelectMarket?: (symbol: string) => void;
};

export default function MarketScanner({ onSelectMarket }: Props) {
  const [open, setOpen] = useState(false);
  const [enabled, setEnabled] = useState(true);
  const [activeTab, setActiveTab] = useState<"over" | "under" | "evenodd">("over");
  const [barrier, setBarrier] = useState(7);
  const [pos, setPos] = useState({ x: window.innerWidth - 80, y: window.innerHeight - 170 });

  const dragging = useRef(false);
  const startPos = useRef({ x: 0, y: 0 });
  const dragOffset = useRef({ x: 0, y: 0 });
  const moved = useRef(false);

  const { results, scanning, lastScan, runScan } = useMarketScanner(enabled);

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    dragging.current = true;
    moved.current = false;
    startPos.current = { x: e.clientX, y: e.clientY };
    dragOffset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.preventDefault();
    e.stopPropagation();
  }, [pos]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      const dx = Math.abs(e.clientX - startPos.current.x);
      const dy = Math.abs(e.clientY - startPos.current.y);
      if (dx > 4 || dy > 4) moved.current = true;
      setPos({ x: e.clientX - dragOffset.current.x, y: e.clientY - dragOffset.current.y });
    };
    const onMouseUp = () => { dragging.current = false; };
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
    return () => {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    };
  }, []);

  const handleClick = () => {
    if (moved.current) return;
    if (!enabled) setEnabled(true);
    setOpen((o) => !o);
  };

  const getRanked = () => {
    if (activeTab === "evenodd") {
      return [...results].sort((a, b) => Math.max(b.evenScore, b.oddScore) - Math.max(a.evenScore, a.oddScore));
    }
    return [...results].sort((a, b) => {
      const aScore = activeTab === "over" ? (a.overScore[barrier] ?? 0) : (a.underScore[barrier] ?? 0);
      const bScore = activeTab === "over" ? (b.overScore[barrier] ?? 0) : (b.underScore[barrier] ?? 0);
      return bScore - aScore;
    });
  };

  const ranked = getRanked();
  const godMarket = ranked[0];

  const getScore = (r: ScanResult) => {
    if (activeTab === "over") return r.overScore[barrier] ?? 0;
    if (activeTab === "under") return r.underScore[barrier] ?? 0;
    return Math.max(r.evenScore, r.oddScore);
  };

  const sigColor = (s: number) =>
    s > 10 ? "#22c55e" : s > 5 ? "#f59e0b" : s > 0 ? "#6b7280" : "#ef4444";
  const sigLabel = (s: number) =>
    s > 10 ? "STRONG" : s > 5 ? "GOOD" : s > 0 ? "WEAK" : "NONE";

  const explainLogic = () => {
    if (activeTab === "over") {
      if (barrier === 3 || barrier === 4)
        return `Over ${barrier} TREND: digits 0,1,2 must be LEAST appearing (most digits above ${barrier}).`;
      return `Over ${barrier} REVERSAL: digits ${barrier + 1}–9 underrepresented — they're due.`;
    }
    if (activeTab === "under") {
      if (barrier === 5 || barrier === 6)
        return `Under ${barrier} TREND: digits 0–3 most appearing + digits 5–9 least appearing.`;
      return `Under ${barrier} REVERSAL: digits 0–${barrier - 1} underrepresented — they're due.`;
    }
    return "Even/Odd REVERSAL: whichever parity is underrepresented vs 50% is due.";
  };

  // Panel opens above the button
  const panelStyle: React.CSSProperties = {
    position: "absolute",
    bottom: "70px",
    right: "0",
    width: "340px",
    background: "#111827",
    borderRadius: "20px",
    border: "1px solid rgba(99,102,241,0.35)",
    boxShadow: "0 -10px 40px rgba(0,0,0,0.6)",
    overflow: "hidden",
    zIndex: 1001,
  };

  return (
    <div style={{ position: "fixed", left: pos.x, top: pos.y, zIndex: 1000, userSelect: "none" }}>
      {/* Panel */}
      {open && (
        <div style={panelStyle}>
          {/* Header */}
          <div style={{ padding: "14px 16px", background: "linear-gradient(135deg,#6366f1,#8b5cf6)", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: "14px" }}>🤖 AI Market Scanner</div>
              <div style={{ fontSize: "10px", opacity: 0.8 }}>
                {scanning ? "⟳ Scanning markets..." : lastScan ? `Scanned ${lastScan.toLocaleTimeString()}` : "Tap Scan to start"}
              </div>
            </div>
            <div style={{ display: "flex", gap: "6px", alignItems: "center" }}>
              <button
                onClick={runScan}
                disabled={scanning}
                style={{ background: "rgba(255,255,255,0.2)", border: "none", color: "white", padding: "5px 10px", borderRadius: "8px", cursor: "pointer", fontSize: "11px", fontWeight: 600 }}
              >
                {scanning ? "..." : "↻ Scan"}
              </button>
              <button
                onClick={() => setOpen(false)}
                style={{ background: "rgba(0,0,0,0.25)", border: "none", color: "white", width: "26px", height: "26px", borderRadius: "50%", cursor: "pointer", fontSize: "16px", lineHeight: 1 }}
              >
                ×
              </button>
            </div>
          </div>

          {/* Tabs */}
          <div style={{ display: "flex", borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
            {(["over", "under", "evenodd"] as const).map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                style={{ flex: 1, padding: "9px", background: activeTab === tab ? "rgba(99,102,241,0.2)" : "transparent", border: "none", borderBottom: activeTab === tab ? "2px solid #6366f1" : "2px solid transparent", color: activeTab === tab ? "white" : "rgba(255,255,255,0.4)", cursor: "pointer", fontSize: "11px", fontWeight: 600 }}
              >
                {tab === "over" ? "OVER" : tab === "under" ? "UNDER" : "EVEN/ODD"}
              </button>
            ))}
          </div>

          {/* Barrier */}
          {activeTab !== "evenodd" && (
            <div style={{ display: "flex", gap: "5px", padding: "9px 12px", flexWrap: "wrap", borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
              {BARRIERS.map((b) => (
                <button key={b} onClick={() => setBarrier(b)}
                  style={{ padding: "4px 9px", borderRadius: "7px", border: "none", background: barrier === b ? "#6366f1" : "#1f2937", color: "white", cursor: "pointer", fontSize: "11px", fontWeight: barrier === b ? 700 : 400 }}
                >
                  {activeTab === "over" ? `>${b}` : `<${b}`}
                </button>
              ))}
            </div>
          )}

          {/* Logic */}
          <div style={{ padding: "7px 12px", fontSize: "11px", color: "rgba(255,255,255,0.4)", background: "rgba(99,102,241,0.05)", borderBottom: "1px solid rgba(255,255,255,0.06)", lineHeight: 1.5 }}>
            {explainLogic()}
          </div>

          {/* God market */}
          {results.length > 0 && godMarket && (
            <div style={{ padding: "10px 12px", borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
              <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.35)", marginBottom: "5px" }}>⚡ GOD MARKET</div>
              <div
                onClick={() => { onSelectMarket?.(godMarket.market.symbol); setOpen(false); }}
                style={{ background: "rgba(34,197,94,0.1)", border: "1px solid rgba(34,197,94,0.35)", borderRadius: "12px", padding: "10px 14px", display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer" }}
              >
                <div>
                  <div style={{ fontWeight: 700, fontSize: "15px", color: "#22c55e" }}>{godMarket.market.label}</div>
                  <div style={{ fontSize: "11px", color: "rgba(255,255,255,0.45)", marginTop: "2px" }}>
                    Score: +{getScore(godMarket).toFixed(1)} · {activeTab === "evenodd" ? (godMarket.evenScore > godMarket.oddScore ? "EVEN" : "ODD") : `${activeTab.toUpperCase()} ${barrier}`}
                  </div>
                </div>
                <div style={{ background: "#22c55e", color: "black", padding: "4px 9px", borderRadius: "7px", fontSize: "10px", fontWeight: 700 }}>USE</div>
              </div>
            </div>
          )}

          {/* Rankings */}
          <div style={{ maxHeight: "220px", overflowY: "auto", padding: "6px 12px 12px" }}>
            {scanning && results.length === 0 && (
              <div style={{ textAlign: "center", padding: "18px", color: "rgba(255,255,255,0.35)", fontSize: "12px" }}>Scanning markets...</div>
            )}
            {ranked.map((r, idx) => {
              const score = getScore(r);
              return (
                <div key={r.market.symbol} onClick={() => { onSelectMarket?.(r.market.symbol); setOpen(false); }}
                  style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 9px", borderRadius: "9px", marginBottom: "3px", background: idx === 0 ? "rgba(34,197,94,0.07)" : "rgba(255,255,255,0.02)", cursor: "pointer", border: idx === 0 ? "1px solid rgba(34,197,94,0.18)" : "1px solid transparent" }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: "7px" }}>
                    <div style={{ width: "18px", height: "18px", borderRadius: "50%", background: idx === 0 ? "#22c55e" : idx === 1 ? "#f59e0b" : "#374151", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "9px", fontWeight: 700, color: idx < 2 ? "black" : "white" }}>{idx + 1}</div>
                    <div style={{ fontSize: "12px" }}>{r.market.label}</div>
                  </div>
                  <div style={{ display: "flex", gap: "5px", alignItems: "center" }}>
                    <span style={{ fontSize: "10px", color: sigColor(score), fontWeight: 600 }}>{sigLabel(score)}</span>
                    <span style={{ fontSize: "11px", fontWeight: 700, color: score > 0 ? "#22c55e" : "#ef4444" }}>{score > 0 ? "+" : ""}{score.toFixed(1)}</span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Floating button */}
      <div
        onMouseDown={onMouseDown}
        onClick={handleClick}
        style={{ width: "58px", height: "58px", borderRadius: "50%", background: "linear-gradient(135deg,#6366f1,#8b5cf6)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", cursor: "grab", boxShadow: open ? "0 0 0 3px rgba(99,102,241,0.4), 0 6px 24px rgba(99,102,241,0.5)" : "0 4px 20px rgba(99,102,241,0.5)", border: "2px solid rgba(255,255,255,0.18)", transition: "box-shadow 0.2s" }}
      >
        <div style={{ fontSize: "22px", lineHeight: 1 }}>🤖</div>
        <div style={{ fontSize: "8px", fontWeight: 700, color: "white", letterSpacing: "0.03em", marginTop: "2px" }}>SCAN</div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import type { DigitStats, ScanResult, KimzMessage } from "../types";

type Props = {
  stats: DigitStats;
  marketLabel: string;
  scanResults: ScanResult[];
};

function uid() {
  return Math.random().toString(36).slice(2);
}

function getLogicType(tradeType: "over" | "under", barrier: number) {
  if (tradeType === "over" && (barrier === 3 || barrier === 4)) return "trend-up";
  if (tradeType === "under" && (barrier === 5 || barrier === 6)) return "trend-down";
  return "reversal";
}

function describeOverLogic(barrier: number) {
  if (getLogicType("over", barrier) === "trend-up")
    return `Over ${barrier} uses TREND logic: digits 0,1,2 must be the LEAST appearing. Most digits falling above ${barrier} — confirms upward bias.`;
  return `Over ${barrier} uses REVERSAL logic: digits ${barrier + 1}–9 must be UNDERREPRESENTED (below expected ${(9 - barrier) * 10}%). They are "due" for a reversal upward.`;
}

function describeUnderLogic(barrier: number) {
  if (getLogicType("under", barrier) === "trend-down")
    return `Under ${barrier} uses TREND logic: digits 0,1,2,3 must be MOST appearing AND digits 5–9 must be LEAST appearing. Both conditions needed.`;
  return `Under ${barrier} uses REVERSAL logic: digits 0–${barrier - 1} must be UNDERREPRESENTED (below expected ${barrier * 10}%). They are "due" for a reversal downward.`;
}

function assessOver(barrier: number, stats: DigitStats) {
  const total = Math.max(stats.total, 1);
  const logic = getLogicType("over", barrier);
  if (logic === "trend-up") {
    const lowCount = [0, 1, 2].reduce((s, d) => s + stats.counts[d], 0);
    const lowPct = ((lowCount / total) * 100).toFixed(1);
    const met = parseFloat(lowPct) < 30;
    return { met, detail: `Digits 0,1,2 = ${lowPct}% (need <30%)` };
  }
  const tgt = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
  const tgtPct = ((tgt.reduce((s, d) => s + stats.counts[d], 0) / total) * 100).toFixed(1);
  const exp = ((tgt.length / 10) * 100).toFixed(0);
  return { met: parseFloat(tgtPct) < parseFloat(exp), detail: `Digits ${barrier + 1}–9 = ${tgtPct}% vs expected ${exp}%` };
}

function assessUnder(barrier: number, stats: DigitStats) {
  const total = Math.max(stats.total, 1);
  const logic = getLogicType("under", barrier);
  if (logic === "trend-down") {
    const loPct = (([0, 1, 2, 3].reduce((s, d) => s + stats.counts[d], 0) / total) * 100).toFixed(1);
    const hiPct = (([5, 6, 7, 8, 9].reduce((s, d) => s + stats.counts[d], 0) / total) * 100).toFixed(1);
    const met = parseFloat(loPct) > 40 && parseFloat(hiPct) < 50;
    return { met, detail: `Digits 0–3 = ${loPct}% (>40% needed) | Digits 5–9 = ${hiPct}% (<50% needed)` };
  }
  const tgt = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
  const tgtPct = ((tgt.reduce((s, d) => s + stats.counts[d], 0) / total) * 100).toFixed(1);
  const exp = ((tgt.length / 10) * 100).toFixed(0);
  return { met: parseFloat(tgtPct) < parseFloat(exp), detail: `Digits 0–${barrier - 1} = ${tgtPct}% vs expected ${exp}%` };
}

function kimzRespond(input: string, stats: DigitStats, market: string, scans: ScanResult[]): string {
  const q = input.toLowerCase().trim();
  const top = stats.topDigits[0];
  const low = stats.bottomDigits[0];
  const total = stats.total;

  if (total < 5) return "⏳ Waiting for more live ticks. Give it a few seconds and ask again!";

  const overM = q.match(/over\s*(\d)/);
  if (overM) {
    const b = parseInt(overM[1]);
    const { met, detail } = assessOver(b, stats);
    const logic = describeOverLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.overScore[b] ?? 0) - (a.overScore[b] ?? 0))[0] : null;
    return `📊 **Over ${b} — ${market}**\n\n${logic}\n\nCurrent: ${detail}\n\nSignal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met"}\n\nTop digit: ${top} (${stats.percentages[top]}%) | Low digit: ${low} (${stats.percentages[low]}%)${best ? `\n\n🏆 Best market: **${best.market.label}** (use 🤖 Scanner)` : ""}`;
  }

  const underM = q.match(/under\s*(\d)/);
  if (underM) {
    const b = parseInt(underM[1]);
    const { met, detail } = assessUnder(b, stats);
    const logic = describeUnderLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.underScore[b] ?? 0) - (a.underScore[b] ?? 0))[0] : null;
    return `📊 **Under ${b} — ${market}**\n\n${logic}\n\nCurrent: ${detail}\n\nSignal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met"}\n\nTop digit: ${top} | Low digit: ${low}${best ? `\n\n🏆 Best market: **${best.market.label}**` : ""}`;
  }

  if (q.includes("even") || q.includes("odd")) {
    const due = stats.evenPercent > stats.oddPercent ? "ODD" : "EVEN";
    const duePct = due === "ODD" ? stats.oddPercent : stats.evenPercent;
    const dueDigits = due === "ODD" ? "1,3,5,7,9" : "0,2,4,6,8";
    return `📊 **Even/Odd — ${market}**\n\nEven: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\n\nReversal: **${due}** digits (${dueDigits}) at ${duePct}% — underrepresented and due.\n\nSignal: ${stats.signal}`;
  }

  if (q.includes("best market") || q.includes("god market") || q.includes("which market")) {
    if (!scans.length) return "Tap the 🤖 SCAN button to scan all markets and find the GOD MARKET!";
    const b7 = [...scans].sort((a, z) => (z.overScore[7] ?? 0) - (a.overScore[7] ?? 0))[0];
    const b4 = [...scans].sort((a, z) => (z.overScore[4] ?? 0) - (a.overScore[4] ?? 0))[0];
    const u5 = [...scans].sort((a, z) => (z.underScore[5] ?? 0) - (a.underScore[5] ?? 0))[0];
    const ev = [...scans].sort((a, z) => z.evenScore - a.evenScore)[0];
    return `🏆 **GOD Markets (${scans.length} scanned):**\n\nOver 7 (reversal): **${b7?.market.label}**\nOver 4 (trend↑): **${b4?.market.label}**\nUnder 5 (trend↓): **${u5?.market.label}**\nEven: **${ev?.market.label}**\n\nUse 🤖 Scanner for full rankings!`;
  }

  if (q.includes("logic") || (q.includes("how") && q.includes("work"))) {
    return `🤖 **Signal Logic:**\n\n**Over 3/4 → TREND ↑**: digits 0,1,2 must be LEAST appearing\n**Over 5–8 → REVERSAL**: digits above barrier underrepresented (due)\n**Under 5/6 → TREND ↓**: digits 0–3 MOST appearing + digits 5–9 LEAST\n**Under 1–4/7–8 → REVERSAL**: digits below barrier underrepresented\n\n⚠️ Educational only.`;
  }

  if (q.includes("distribution") || q.includes("digits") || q.includes("count")) {
    return `📡 **${market} Distribution (${total} ticks):**\n\n${stats.counts.map((c, i) => `Digit ${i}: ${stats.percentages[i]}%${i === top ? " 🔥" : i === low ? " ❄️" : ""}`).join("\n")}`;
  }

  if (q.includes("confidence")) {
    return `🤖 **AI Confidence: ${stats.aiConfidence}%**\n\nMeasures how strongly the digit distribution deviates from the theoretical 10% each.\n\nHighest: digit ${top} at ${stats.percentages[top]}% | Lowest: digit ${low} at ${stats.percentages[low]}%`;
  }

  if (q.match(/^(hi|hello|hey|sup|yo)/)) {
    return `👋 Hey! I'm **Kimz Analysis** — live on ${market}.\n\nI know the exact logic for every barrier:\n• Over 3/4 → TREND (digits 0,1,2 must be rare)\n• Over 5–8 → REVERSAL (target digits due)\n• Under 5/6 → TREND (0–3 dominating, 5–9 rare)\n• Under others → REVERSAL\n\nTry: "over 4", "under 5", "best market?", "logic"`;
  }

  return `📊 **${market}** (${total} ticks)\n\n🔥 Most: **${top}** (${stats.percentages[top]}%) | ❄️ Least: **${low}** (${stats.percentages[low]}%)\nEven: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%\n${stats.signal}\n\nAsk: "over 7", "under 5", "over 4", "best market?", or "logic"`;
}

export default function KimzAnalysis({ stats, marketLabel, scanResults }: Props) {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState<KimzMessage[]>([
    { id: uid(), role: "kimz", ts: Date.now(), text: "👋 Hi! I'm **Kimz Analysis** — your AI trading assistant.\n\nI know the exact signal logic for every barrier. Ask me:\n• \"analyze over 4\" or \"over 7\"\n• \"under 5 signal\"\n• \"best market?\"\n• \"explain logic\"" },
  ]);
  const [input, setInput] = useState("");
  const [pos, setPos] = useState({ x: window.innerWidth - 80, y: window.innerHeight - 90 });
  const inputRef = useRef<HTMLInputElement>(null);

  const dragging = useRef(false);
  const startPos = useRef({ x: 0, y: 0 });
  const dragOffset = useRef({ x: 0, y: 0 });
  const moved = useRef(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    dragging.current = true;
    moved.current = false;
    startPos.current = { x: e.clientX, y: e.clientY };
    dragOffset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.preventDefault();
    e.stopPropagation();
  }, [pos]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      const dx = Math.abs(e.clientX - startPos.current.x);
      const dy = Math.abs(e.clientY - startPos.current.y);
      if (dx > 4 || dy > 4) moved.current = true;
      setPos({ x: e.clientX - dragOffset.current.x, y: e.clientY - dragOffset.current.y });
    };
    const onMouseUp = () => { dragging.current = false; };
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
    return () => {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    };
  }, []);

  const handleClick = () => {
    if (moved.current) return;
    setOpen((o) => {
      if (!o) setTimeout(() => inputRef.current?.focus(), 100);
      return !o;
    });
  };

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const send = (text?: string) => {
    const t = (text ?? input).trim();
    if (!t) return;
    const userMsg: KimzMessage = { id: uid(), role: "user", text: t, ts: Date.now() };
    const replyMsg: KimzMessage = { id: uid(), role: "kimz", text: kimzRespond(t, stats, marketLabel, scanResults), ts: Date.now() };
    setMessages((m) => [...m, userMsg, replyMsg]);
    setInput("");
    setTimeout(() => inputRef.current?.focus(), 50);
  };

  const fmt = (text: string) =>
    text.split("\n").map((line, i) => (
      <div key={i} style={{ lineHeight: 1.55 }}
        dangerouslySetInnerHTML={{ __html: line.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>") || "&nbsp;" }}
      />
    ));

  const suggestions = ["over 4", "under 5", "over 7", "best market?", "explain logic"];

  return (
    <div style={{ position: "fixed", left: pos.x, top: pos.y, zIndex: 998, userSelect: "none" }}>
