              >
                {q}
              </button>
            ))}
          </div>

          {/* Messages */}
          <div style={{ height: "300px", overflowY: "auto", padding: "12px 10px", display: "flex", flexDirection: "column", gap: "10px" }}>
            {messages.map((msg) => (
              <div key={msg.id} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start" }}>
                {msg.role === "kimz" && (
                  <div style={{ width: "26px", height: "26px", borderRadius: "50%", background: "linear-gradient(135deg,#f59e0b,#ef4444)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "13px", flexShrink: 0, marginRight: "6px", alignSelf: "flex-end" }}>K</div>
                )}
                <div style={{ maxWidth: "80%", padding: "9px 13px", borderRadius: msg.role === "user" ? "16px 16px 4px 16px" : "16px 16px 16px 4px", background: msg.role === "user" ? "linear-gradient(135deg,#f59e0b,#ef4444)" : "#1f2937", fontSize: "12px", color: "white", border: msg.role === "kimz" ? "1px solid rgba(255,255,255,0.07)" : "none" }}>
                  {fmt(msg.text)}
                </div>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>

          {/* Input */}
          <div style={{ display: "flex", gap: "7px", padding: "10px", borderTop: "1px solid rgba(255,255,255,0.08)", background: "#0f172a", flexShrink: 0 }}>
            <input
              ref={inputRef}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); send(); } }}
              placeholder="Type your question..."
              style={{ flex: 1, background: "#1f2937", border: "1px solid rgba(255,255,255,0.1)", borderRadius: "12px", padding: "9px 14px", color: "white", fontSize: "13px", outline: "none", fontFamily: "inherit" }}
            />
            <button
              onClick={() => send()}
              style={{ background: "linear-gradient(135deg,#f59e0b,#ef4444)", border: "none", borderRadius: "12px", padding: "9px 14px", color: "white", cursor: "pointer", fontWeight: 700, fontSize: "16px", lineHeight: 1 }}
            >
              ↑
            </button>
          </div>
        </div>
      )}

      {/* Floating button */}
      <div
        onMouseDown={onMouseDown}
        onClick={handleClick}
        style={{ width: "58px", height: "58px", borderRadius: "50%", background: "linear-gradient(135deg,#f59e0b,#ef4444)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", cursor: "grab", boxShadow: open ? "0 0 0 3px rgba(245,158,11,0.4), 0 6px 24px rgba(245,158,11,0.5)" : "0 4px 20px rgba(245,158,11,0.5)", border: "2px solid rgba(255,255,255,0.18)", transition: "box-shadow 0.2s" }}
      >
        <div style={{ fontSize: "22px", lineHeight: 1 }}>💬</div>
        <div style={{ fontSize: "8px", fontWeight: 700, color: "white", marginTop: "2px" }}>KIMZ</div>
      </div>
    </div>
  );
}

