    13→
    14→/**
    15→ * Scoring rules per barrier (reversal vs trend logic):
    16→ *
    17→ * Over 7 / Over 8  → REVERSAL: digits ABOVE barrier are underrepresented (due)
    18→ *                    Score = expected%(digits>barrier) − actual%
    19→ *
    20→ * Over 5 / Over 6  → REVERSAL: same (digits above barrier underrepresented)
    21→ *
    22→ * Over 3 / Over 4  → TREND: digits 0,1,2 are the LEAST appearing (most digits >3)
    23→ *                    Score = expected%(0,1,2=30%) − actual%(0,1,2)
    24→ *                    Higher = 0-2 are rarer = trend above 3 is strong
    25→ *
    26→ * Over 1 / Over 2  → REVERSAL (default)
    27→ *
    28→ * Under 5 / Under 6 → TREND: digits 0,1,2,3 are MOST appearing, digits >4 are least
    29→ *                    Score = actual%(0,1,2,3) − expected%(40%)
    30→ *
    31→ * Under 1-4 / Under 7-8 → REVERSAL: digits BELOW barrier underrepresented (due)
    32→ *                    Score = expected%(digits<barrier) − actual%
    33→ */
    34→function scoreOver(barrier: number, counts: number[], total: number): number {
    35→  if (total === 0) return 0;
    36→
    37→  if (barrier === 3 || barrier === 4) {
    38→    // TREND: digits 0,1,2 should be least appearing
    39→    const lowDigits = [0, 1, 2];
    40→    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    41→    const lowPct = (lowCount / total) * 100;
    42→    const expectedPct = 30; // 3 digits × 10%
    43→    return expectedPct - lowPct; // higher = 0-2 are rarer = upward trend
    44→  }
    45→
    46→  // Default REVERSAL: digits above barrier should be underrepresented (due)
    47→  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d > barrier);
    48→  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
    49→  const targetPct = (targetCount / total) * 100;
    50→  const expectedPct = (targetDigits.length / 10) * 100;
    51→  return expectedPct - targetPct;
    52→}
    53→
    54→function scoreUnder(barrier: number, counts: number[], total: number): number {
    55→  if (total === 0) return 0;
    56→
    57→  if (barrier === 5 || barrier === 6) {
    58→    // TREND: digits 0,1,2,3 are MOST appearing AND digits >4 are least
    59→    const lowDigits = [0, 1, 2, 3];
    60→    const lowCount = lowDigits.reduce((s, d) => s + counts[d], 0);
    61→    const lowPct = (lowCount / total) * 100;
    62→    const expectedPct = 40; // 4 digits × 10%
    63→    return lowPct - expectedPct; // higher = 0-3 appear more than expected = downward trend
    64→  }
    65→
    66→  // Default REVERSAL: digits below barrier should be underrepresented (due)
    67→  const targetDigits = Array.from({ length: 10 }, (_, i) => i).filter((d) => d < barrier);
    68→  const targetCount = targetDigits.reduce((s, d) => s + counts[d], 0);
    69→  const targetPct = (targetCount / total) * 100;
    70→  const expectedPct = (targetDigits.length / 10) * 100;
    71→  return expectedPct - targetPct;
    72→}
