function kimzRespond(input: string, stats: DigitStats, market: string, scans: ScanResult[]): string {
  const q = input.toLowerCase().trim();
  const top = stats.topDigits[0];
  const low = stats.bottomDigits[0];
  const total = stats.total;

  if (total < 5) return "⏳ Waiting for more live ticks. Give it a few seconds and ask again!";

  const overM = q.match(/over\s*(\d)/);
  if (overM) {
    const b = parseInt(overM[1]);
    const { met, detail } = assessOver(b, stats);
    const logic = describeOverLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.overScore[b] ?? 0) - (a.overScore[b] ?? 0))[0] : null;
    return `📊 **Over ${b} — ${market}**

${logic}

Current: ${detail}

Signal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met"}

Top digit: ${top} (${stats.percentages[top]}%) | Low digit: ${low} (${stats.percentages[low]}%)${best ? `

🏆 Best market: **${best.market.label}** (use 🤖 Scanner)` : ""}`;
  }

  const underM = q.match(/under\s*(\d)/);
  if (underM) {
    const b = parseInt(underM[1]);
    const { met, detail } = assessUnder(b, stats);
    const logic = describeUnderLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.underScore[b] ?? 0) - (a.underScore[b] ?? 0))[0] : null;
    return `📊 **Under ${b} — ${market}**

${logic}

Current: ${detail}

Signal: ${met ? "✅ GOD MARKET CONDITION MET" : "❌ Condition not met"}

Top digit: ${top} | Low digit: ${low}${best ? `

🏆 Best market: **${best.market.label}**` : ""}`;
  }

  if (q.includes("even") || q.includes("odd")) {
    const due = stats.evenPercent > stats.oddPercent ? "ODD" : "EVEN";
    const duePct = due === "ODD" ? stats.oddPercent : stats.evenPercent;
    const dueDigits = due === "ODD" ? "1,3,5,7,9" : "0,2,4,6,8";
    return `📊 **Even/Odd — ${market}**

Even: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%

Reversal: **${due}** digits (${dueDigits}) at ${duePct}% — underrepresented and due.

Signal: ${stats.signal}`;
  }

  if (q.includes("best market") || q.includes("god market") || q.includes("which market")) {
    if (!scans.length) return "Tap the 🤖 SCAN button to scan all markets and find the GOD MARKET!";
    const b7 = [...scans].sort((a, z) => (z.overScore[7] ?? 0) - (a.overScore[7] ?? 0))[0];
    const b4 = [...scans].sort((a, z) => (z.overScore[4] ?? 0) - (a.overScore[4] ?? 0))[0];
    const u5 = [...scans].sort((a, z) => (z.underScore[5] ?? 0) - (a.underScore[5] ?? 0))[0];
    const ev = [...scans].sort((a, z) => z.evenScore - a.evenScore)[0];
    return `🏆 **GOD Markets (${scans.length} scanned):**

Over 7 (reversal): **${b7?.market.label}**
Over 4 (trend↑): **${b4?.market.label}**
Under 5 (trend↓): **${u5?.market.label}**
Even: **${ev?.market.label}**

Use 🤖 Scanner for full rankings!`;
  }

  if (q.includes("logic") || (q.includes("how") && q.includes("work"))) {
    return `🤖 **Signal Logic:**

**Over 3/4 → TREND ↑**: digits 0,1,2 must be LEAST appearing
**Over 5–8 → REVERSAL**: digits above barrier underrepresented (due)
**Under 5/6 → TREND ↓**: digits 0–3 MOST appearing + digits 5–9 LEAST
**Under 1–4/7–8 → REVERSAL**: digits below barrier underrepresented

⚠️ Educational only.`;
  }

  if (q.includes("distribution") || q.includes("digits") || q.includes("count")) {
    return `📡 **${market} Distribution (${total} ticks):**

${stats.counts.map((c, i) => `Digit ${i}: ${stats.percentages[i]}%${i === top ? " 🔥" : i === low ? " ❄️" : ""}`).join("
")}`;
  }

  if (q.includes("confidence")) {
    return `🤖 **AI Confidence: ${stats.aiConfidence}%**

Measures how strongly the digit distribution deviates from the theoretical 10% each.

Highest: digit ${top} at ${stats.percentages[top]}% | Lowest: digit ${low} at ${stats.percentages[low]}%`;
  }

  if (q.match(/^(hi|hello|hey|sup|yo)/)) {
    return `👋 Hey! I'm **Kimz Analysis** — live on ${market}.

I know the exact logic for every barrier:
• Over 3/4 → TREND (digits 0,1,2 must be rare)
• Over 5–8 → REVERSAL (target digits due)
• Under 5/6 → TREND (0–3 dominating, 5–9 rare)
• Under others → REVERSAL

Try: "over 4", "under 5", "best market?", "logic"`;
  }

  return `📊 **${market}** (${total} ticks)

🔥 Most: **${top}** (${stats.percentages[top]}%) | ❄️ Least: **${low}** (${stats.percentages[low]}%)
Even: ${stats.evenPercent}% | Odd: ${stats.oddPercent}%
${stats.signal}

Ask: "over 7", "under 5", "over 4", "best market?", or "logic"`;
}

arguments.new_string:
function kimzRespond(input: string, stats: DigitStats, market: string, scans: ScanResult[]): string {
  const q = input.toLowerCase().trim();
  const top = stats.topDigits[0];
  const bot = stats.bottomDigits[0];
  const total = stats.total;

  // --- greetings & acknowledgments ---
  if (q.match(/^(hi|hello|hey|sup|yo|hii+|heya|howdy)/)) {
    return `👋 Hey! I'm **Kimz Analysis** — live on **${market}** with ${total} ticks so far.

Current hottest digit: **${top}** (${stats.percentages[top]}%) | Coldest: **${bot}** (${stats.percentages[bot]}%)

I know the exact signal logic for every barrier. Try:
• "over 4" or "under 5"
• "best market?"
• "what should I trade?"
• "explain logic"`;
  }
  if (q.match(/^(thanks|thank you|thx|ty|ok|okay|got it|nice|cool|great|perfect|good|wow|amazing|lol|haha|yep|yes|no|nope|sure)/)) {
    const tips = [
      `You're welcome! 😊 On **${market}** right now: digit **${top}** is dominant at ${stats.percentages[top]}%. Ask me anything — "over 7", "under 5", "best market?"`,
      `Anytime! 🤖 Market update: Even ${stats.evenPercent}% vs Odd ${stats.oddPercent}% — ${stats.evenPercent > stats.oddPercent ? "ODD is underrepresented and due" : "EVEN is underrepresented and due"}. Ask me a barrier to analyze!`,
      `😎 Glad to help! **${market}** has ${total} ticks. Digit **${bot}** is the coldest at ${stats.percentages[bot]}% — potentially DUE. Want me to check a barrier for it?`,
    ];
    return tips[Math.floor(Math.random() * tips.length)];
  }

  // --- waiting for data ---
  if (total < 5) return `⏳ Still connecting to **${market}**... Give it a moment and ask again once ticks start coming in!`;

  // --- OVER barrier ---
  const overM = q.match(/over\s*(\d)/);
  if (overM) {
    const b = parseInt(overM[1]);
    if (b < 1 || b > 8) return `⚠️ Over barrier must be between 1 and 8. Try "over 3", "over 5", "over 7" etc.`;
    const { met, detail } = assessOver(b, stats);
    const logic = describeOverLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.overScore[b] ?? 0) - (a.overScore[b] ?? 0))[0] : null;
    const confidence = met ? Math.min(95, 65 + Math.round(stats.aiConfidence * 0.3)) : Math.max(20, 50 - Math.round(stats.aiConfidence * 0.2));
    return `📊 **Over ${b} — ${market}**

${logic}

Current: ${detail}

Signal: ${met ? `✅ GOD MARKET CONDITION MET (${confidence}% confidence)` : "❌ Conditions not yet met — wait for more ticks"}

Hottest: **${top}** (${stats.percentages[top]}%) | Coldest: **${bot}** (${stats.percentages[bot]}%)${best ? `

🏆 Best market for Over ${b}: **${best.market.label}**` : "

💡 Tap 🤖 SCAN to find the best market for this barrier"}`;
  }

  // --- UNDER barrier ---
  const underM = q.match(/under\s*(\d)/);
  if (underM) {
    const b = parseInt(underM[1]);
    if (b < 1 || b > 8) return `⚠️ Under barrier must be between 1 and 8. Try "under 3", "under 5", "under 6" etc.`;
    const { met, detail } = assessUnder(b, stats);
    const logic = describeUnderLogic(b);
    const best = scans.length > 0 ? [...scans].sort((a, z) => (z.underScore[b] ?? 0) - (a.underScore[b] ?? 0))[0] : null;
    const confidence = met ? Math.min(95, 65 + Math.round(stats.aiConfidence * 0.3)) : Math.max(20, 50 - Math.round(stats.aiConfidence * 0.2));
    return `📊 **Under ${b} — ${market}**

${logic}

Current: ${detail}

Signal: ${met ? `✅ GOD MARKET CONDITION MET (${confidence}% confidence)` : "❌ Conditions not yet met — wait for more ticks"}

Hottest: **${top}** (${stats.percentages[top]}%) | Coldest: **${bot}** (${stats.percentages[bot]}%)${best ? `

🏆 Best market for Under ${b}: **${best.market.label}**` : "

💡 Tap 🤖 SCAN to find the best market for this barrier"}`;
  }

  // --- digit-specific questions: "digit 7", "what is 3 doing", "tell me about 5" ---
  const digitM = q.match(/ digit\s*(\d) /) || q.match(/ about\s*(\d) /) || q.match(/ (\d)\s*(doing|look|stat|pct|percent|appear|show|at) /);
  if (digitM) {
    const d = parseInt(digitM[1]);
    const pct = parseFloat(stats.percentages[d]);
    const count = stats.counts[d];
    const status = pct < 6 ? "🔵 DUE (very underrepresented)" : pct < 8.5 ? "🟣 LOW" : pct < 11.5 ? "⬜ NORMAL" : pct < 14 ? "🟡 HIGH" : "🔴 HOT (oversaturated)";
    const deviation = (pct - 10).toFixed(1);
    return `🔢 **Digit ${d} on ${market}**

Appearances: **${count}** out of ${total} ticks
Frequency: **${pct.toFixed(1)}%** (expected 10%)
Deviation: ${parseFloat(deviation) >= 0 ? "+" : ""}${deviation}%
Status: ${status}

${pct < 8 ? `Digit ${d} is BELOW expected — statistically DUE to appear more. Good for MATCHES on digit ${d}.` : pct > 12 ? `Digit ${d} is ABOVE expected — may slow down. Consider DIFFERS from digit ${d}.` : `Digit ${d} is within normal range — no strong edge currently.`}`;
  }

  // --- number-only input: treat as "analyze this digit/barrier" ---
  const numOnly = q.match(/^\s*(\d)\s*$/);
  if (numOnly) {
    const n = parseInt(numOnly[1]);
    const pct = parseFloat(stats.percentages[n]);
    const { met: overMet } = assessOver(n, stats);
    const { met: underMet } = n >= 1 ? assessUnder(n, stats) : { met: false };
    return `🔢 **Digit ${n} Analysis — ${market}**

Frequency: **${pct.toFixed(1)}%** (${stats.counts[n]}× in ${total} ticks)
${pct < 10 ? `❄️ Below average — DUE` : `🔥 Above average — HOT`}

**As a barrier:**
Over ${n}: ${overMet ? "✅ Signal active" : "❌ No signal"} · ${describeOverLogic(n).split(":")[0]}
${n >= 1 ? `Under ${n}: ${underMet ? "✅ Signal active" : "❌ No signal"} · ${describeUnderLogic(n).split(":")[0]}` : ""}

Ask "over ${n}" or "under ${n}" for full barrier analysis.`;
  }

  // --- EVEN / ODD ---
  if (q.includes("even") || q.includes("odd")) {
    const due = stats.evenPercent > stats.oddPercent ? "ODD" : "EVEN";
    const duePct = due === "ODD" ? stats.oddPercent : stats.evenPercent;
    const dueDigits = due === "ODD" ? "1,3,5,7,9" : "0,2,4,6,8";
    const strength = Math.abs(stats.evenPercent - stats.oddPercent).toFixed(1);
    return `📊 **Even/Odd — ${market}**

Even: **${stats.evenPercent}%** | Odd: **${stats.oddPercent}%**
Imbalance: ${strength}%

${parseFloat(strength) > 5 ? `✅ Strong signal: **${due}** is DUE` : `⚠️ Weak signal: imbalance only ${strength}% — wait for more separation`}

Due digits (${due}): ${dueDigits} — avg ${duePct}%

${stats.signal}`;
  }

  // --- MATCHES / DIFFERS ---
  if (q.includes("match") || q.includes("differ") || q.includes("same")) {
    return `🎯 **Matches & Differs — ${market}**

Matches: **${stats.matchesProbability}%** probability
Differs: **${stats.differsProbability}%** probability

Hottest digit: **${top}** (${stats.percentages[top]}%) — if it keeps repeating, MATCHES is strong
Coldest digit: **${bot}** (${stats.percentages[bot]}%) — likely to change next = DIFFERS signal

${stats.matchesProbability > stats.differsProbability ? "🟢 Lean: **MATCHES** has slight edge" : "🟢 Lean: **DIFFERS** has slight edge"}`;
  }

  // --- BEST MARKET / GOD MARKET / WHICH MARKET ---
  if (q.includes("best market") || q.includes("god market") || q.includes("which market") || q.includes("best trade") || q.includes("scan")) {
    if (!scans.length) return `🤖 No scan data yet! Tap the **🤖 SCAN** button (floating purple button) to scan all 10 markets.

I'll then tell you which market is GOD for every barrier — Over 3/4/5/6/7/8 and Under 3/4/5/6/7/8!`;
    const b7 = [...scans].sort((a, z) => (z.overScore[7] ?? 0) - (a.overScore[7] ?? 0))[0];
    const b4 = [...scans].sort((a, z) => (z.overScore[4] ?? 0) - (a.overScore[4] ?? 0))[0];
    const u5 = [...scans].sort((a, z) => (z.underScore[5] ?? 0) - (a.underScore[5] ?? 0))[0];
    const u6 = [...scans].sort((a, z) => (z.underScore[6] ?? 0) - (a.underScore[6] ?? 0))[0];
    const ev = [...scans].sort((a, z) => z.evenScore - a.evenScore)[0];
    const od = [...scans].sort((a, z) => z.oddScore - a.oddScore)[0];
    return `🏆 **GOD Markets (${scans.length} scanned):**

Over 7 (reversal): **${b7?.market.label}**
Over 4 (trend↑): **${b4?.market.label}**
Under 5 (trend↓): **${u5?.market.label}**
Under 6 (trend↓): **${u6?.market.label}**
Even signal: **${ev?.market.label}**
Odd signal: **${od?.market.label}**

💡 Ask "over 7" or "under 5" on any market for full signal details!`;
  }

  // --- WHAT TO TRADE / RECOMMEND ---
  if (q.includes("what should") || q.includes("recommend") || q.includes("what to trade") || q.includes("suggest") || q.includes("advice") || q.includes("best bet") || q.includes("what trade")) {
    const allOver = [3,4,5,6,7,8].map(b => ({ b, type:"over", met: assessOver(b, stats).met, score: b >= 5 ? (parseFloat(stats.percentages.slice(b+1).join(" ")) || 0) : 0 }));
    const allUnder = [3,4,5,6,7,8].map(b => ({ b, type:"under", met: assessUnder(b, stats).met }));
    const metOver = allOver.filter(x => x.met).map(x => `Over ${x.b}`);
    const metUnder = allUnder.filter(x => x.met).map(x => `Under ${x.b}`);
    const allMet = [...metOver, ...metUnder];
    const evenDue = stats.evenPercent < 48 ? "EVEN" : stats.oddPercent < 48 ? "ODD" : null;
