import { createContext, useContext, useState, useEffect } from "react";

export type Theme = {
  isDark: boolean;
  root: string;
  card: string;
  cardInner: string;
  cardDeep: string;
  text: string;
  textSub: string;
  textMid: string;
  textLow: string;
  border: string;
  borderMid: string;
  borderHi: string;
  barTrack: string;
  shadow: string;
};

const DARK: Theme = {
  isDark: true,
  root: "#0b1220",
  card: "#111827",
  cardInner: "#1f2937",
  cardDeep: "#0f172a",
  text: "white",
  textSub: "rgba(255,255,255,0.4)",
  textMid: "rgba(255,255,255,0.55)",
  textLow: "rgba(255,255,255,0.3)",
  border: "rgba(255,255,255,0.05)",
  borderMid: "rgba(255,255,255,0.08)",
  borderHi: "rgba(255,255,255,0.12)",
  barTrack: "rgba(255,255,255,0.08)",
  shadow: "0 10px 25px rgba(0,0,0,0.25)",
};

const LIGHT: Theme = {
  isDark: false,
  root: "#e8eef5",
  card: "#ffffff",
  cardInner: "#f1f5f9",
  cardDeep: "#f8fafc",
  text: "#0f172a",
  textSub: "rgba(15,23,42,0.45)",
  textMid: "rgba(15,23,42,0.58)",
  textLow: "rgba(15,23,42,0.35)",
  border: "rgba(0,0,0,0.07)",
  borderMid: "rgba(0,0,0,0.09)",
  borderHi: "rgba(0,0,0,0.13)",
  barTrack: "rgba(0,0,0,0.07)",
  shadow: "0 6px 20px rgba(0,0,0,0.07)",
};

type ThemeCtx = { theme: Theme; toggleTheme: () => void };
const Ctx = createContext<ThemeCtx>({ theme: DARK, toggleTheme: () => {} });

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [isDark, setIsDark] = useState(() => {
    try { return localStorage.getItem("theme") !== "light"; } catch { return true; }
  });

  const toggleTheme = () => {
    setIsDark((d) => {
      const next = !d;
      try { localStorage.setItem("theme", next ? "dark" : "light"); } catch {}
      return next;
    });
  };

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", isDark ? "dark" : "light");
  }, [isDark]);

  return (
    <Ctx.Provider value={{ theme: isDark ? DARK : LIGHT, toggleTheme }}>
      {children}
    </Ctx.Provider>
  );
}

export function useTheme(): ThemeCtx { return useContext(Ctx); }

