import { useEffect, useReducer, useRef } from "react";
import { MARKETS } from "../types";

const APP_ID = "1089";
const WS_URL = `wss://ws.binaryws.com/websockets/v3?app_id=${APP_ID}`;

function extractLastDigit(quote: number): number {
  return parseInt(quote.toString().slice(-1));
}

export type MarketTickState = {
  counts: number[];
  lastDigit: number;
  lastQuote: number;
  tickCount: number;
};

export type AllMarketsTickState = {
  connected: boolean;
  error: string | null;
  markets: Record<string, MarketTickState>;
};

type Action =
  | { type: "CONNECTED" }
  | { type: "DISCONNECTED" }
  | { type: "ERROR"; error: string }
  | { type: "TICK"; symbol: string; digit: number; quote: number; counts: number[] };

function makeInitialMarkets(): Record<string, MarketTickState> {
  const r: Record<string, MarketTickState> = {};
  for (const m of MARKETS) {
    r[m.symbol] = { counts: Array(10).fill(0), lastDigit: 0, lastQuote: 0, tickCount: 0 };
  }
  return r;
}

const initialState: AllMarketsTickState = {
  connected: false,
  error: null,
  markets: makeInitialMarkets(),
};

function reducer(state: AllMarketsTickState, action: Action): AllMarketsTickState {
  switch (action.type) {
    case "CONNECTED":
      return { ...state, connected: true, error: null };
    case "DISCONNECTED":
      return { ...state, connected: false };
    case "ERROR":
      return { ...state, connected: false, error: action.error };
    case "TICK": {
      const prev = state.markets[action.symbol];
      if (!prev) return state;
      return {
        ...state,
        markets: {
          ...state.markets,
          [action.symbol]: {
            counts: action.counts,
            lastDigit: action.digit,
            lastQuote: action.quote,
            tickCount: prev.tickCount + 1,
          },
        },
      };
    }
    default:
      return state;
  }
}

export function useAllMarketTicks(): AllMarketsTickState {
  const [state, dispatch] = useReducer(reducer, initialState);

  const countsMapRef = useRef<Record<string, number[]>>({});
  const wsRef = useRef<WebSocket | null>(null);

  useEffect(() => {
    const countsMap: Record<string, number[]> = {};
    for (const m of MARKETS) countsMap[m.symbol] = Array(10).fill(0);
    countsMapRef.current = countsMap;

    let destroyed = false;
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;

    function connect() {
      if (destroyed) return;

      const ws = new WebSocket(WS_URL);
      wsRef.current = ws;

      ws.onopen = () => {
        if (destroyed) { ws.close(); return; }
        dispatch({ type: "CONNECTED" });
        for (const market of MARKETS) {
          ws.send(JSON.stringify({ ticks: market.symbol, subscribe: 1 }));
        }
      };

      ws.onmessage = (evt: MessageEvent) => {
        if (destroyed) return;
        try {
          const data = JSON.parse(evt.data as string) as {
            error?: { message: string };
            msg_type?: string;
            tick?: { symbol: string; quote: number };
          };
          if (data.error) return;
          if (data.msg_type === "tick" && data.tick) {
            const { symbol, quote } = data.tick;
            const digit = extractLastDigit(quote);
            const counts = countsMapRef.current[symbol];
            if (!counts) return;
            counts[digit]++;
            dispatch({ type: "TICK", symbol, digit, quote, counts: [...counts] });
          }
        } catch {
          // ignore parse errors
        }
      };

      ws.onerror = () => {
        if (destroyed) return;
        dispatch({ type: "ERROR", error: "Connection error" });
      };

      ws.onclose = () => {
        if (destroyed) return;
        dispatch({ type: "DISCONNECTED" });
        reconnectTimer = setTimeout(connect, 3000);
      };
    }

    connect();

    return () => {
      destroyed = true;
      if (reconnectTimer) clearTimeout(reconnectTimer);
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
        wsRef.current = null;
      }
    };
  }, []);

  return state;
}

